-- Poems batch 426
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuanqu-7205','降桑椹蔡顺奉母・醉中天','刘唐卿','元','元曲','yuanqu','','[]','这雪更塞拥蓝关道，尽蔽了九重霄，岭畔寒梅恰便似舒玉梢。',97,'元曲/yuanqu.json','["这雪更塞拥蓝关道，尽蔽了九重霄，岭畔寒梅恰便似舒玉梢。", "(云)将酒来，仇员外满饮一杯。", "(仇彦达云)老夫饮。", "这雪真乃国家祥瑞也。", "(正末唱)这雪普四海添吉兆，仰圣德黎民安乐。", "满斟白醪，贺丰年万姓歌瑶。"]'),
('yuanqu-7206','降桑椹蔡顺奉母・清江引','刘唐卿','元','元曲','yuanqu','','[]','这雪白来白似白厮赖，(云)这雪若还下在席子上，(唱)恰便似一床白绫被。',57,'元曲/yuanqu.json','["这雪白来白似白厮赖，(云)这雪若还下在席子上，(唱)恰便似一床白绫被。", "铺在热炕上，盖着和衣儿睡，醒来时化了一身水。"]'),
('yuanqu-7207','降桑椹蔡顺奉母・那吒令','刘唐卿','元','元曲','yuanqu','','[]','有钱人最好，锦貂裘暖帽；无钱人困遭，穿补衣衲袄；绕人家乞讨，忍饥寒冻倒。',92,'元曲/yuanqu.json','["有钱人最好，锦貂裘暖帽；无钱人困遭，穿补衣衲袄；绕人家乞讨，忍饥寒冻倒。", "数九天怎过遣？大街上高声叫，战兢兢性命难逃。", "(夏德闰云)人生在天地之间，贫富分其两等，乃自然之理也。", "(正末唱)。"]'),
('yuanqu-7208','降桑椹蔡顺奉母・鹊踏枝','刘唐卿','元','元曲','yuanqu','','[]','富家郎逞英豪，显奢骄，他每便语话言谈，气势偏高。',44,'元曲/yuanqu.json','["富家郎逞英豪，显奢骄，他每便语话言谈，气势偏高。", "腆着脯向人前气傲，他把这贫民每当作儿曹。"]'),
('yuanqu-7209','降桑椹蔡顺奉母・寄生草','刘唐卿','元','元曲','yuanqu','','[]','有钱的高堂上常奢侈，无钱的遭贫寒居瓦窑。',521,'元曲/yuanqu.json','["有钱的高堂上常奢侈，无钱的遭贫寒居瓦窑。", "有钱的列金钗弦管可便心欢乐，无钱的受忄西惶寂寞伤怀抱。", "有钱的逞轩昂马践红尘道，无钱的向人前缩手口难开，则他这贫穷富贵是天道。", "(蔡员外云)众位长者，慢慢的饮酒。", "看有甚么人来？(解子押延岑上)(延岑云)猛烈刚强自古无，平生慷慨不尘俗。", "见义当为真男子，则是我正直无私大丈夫。", "某姓延，名岑，字均义。", "我早生好汉，刚强性鲁，膂力过人。", "我在那长街市上闲行，因见个年少的后生，赶着个年老的打。", "我路见不平，将那年少拉将过来，三拳两脚，过打死了。", "我出首到官，饶我死罪，脊杖了六十，罚我去郑州迭配牢城。", "时遇冬暮天气，纷纷扬扬的下着这般大雪，身上单寒，肚里无食。", "解子哥哥，你看这家儿人家，高房子，大门楼，门前马车嚷闹，必是个豪富之家。", "俺去讨些茶饭食用。", "(解子云)延岑，你可休走了。", "(延岑云)哥哥，小人身做身当，岂敢带累你也？(解子云)你若这般，便好。", "(延岑云)来到门首也。", "我试叫一声。", "大主人家，有那怜悯之心，用不了的茶饭，乞讨些食用。", "(正末云)甚么人在门首，大惊小怪的？我试看去者。", "(蔡员外云)孩儿也，你试看去。", "(正末出门见科，云)一条好汉也。", "兀那壮士，你因何带锁披枷来？(延岑云)哥哥不知。", "小人平昔之间，刚强怀勇，膂力过人。"]'),
('yuanqu-7210','降桑椹蔡顺奉母・金盏儿','刘唐卿','元','元曲','yuanqu','','[]','哥哥你是英豪，逞雄骁。',94,'元曲/yuanqu.json','["哥哥你是英豪，逞雄骁。", "(延岑云)兄弟，我路见不平，把那年少的三拳两脚，就打死了也。", "(正末唱)致伤人命官司行告，郑州迭配见些功劳。", "有一日身荣为官爵。", "青史把名标。", "博一个马靴白象简，金带紫罗袍。"]'),
('yuanqu-7211','降桑椹蔡顺奉母・尾声','刘唐卿','元','元曲','yuanqu','','[]','俺可便离了画阁兰堂，举步登途道，赏瑞雪排筵罢却。',188,'元曲/yuanqu.json','["俺可便离了画阁兰堂，举步登途道，赏瑞雪排筵罢却。", "(蔡员外云)孩儿也，为人在世，得欢当作乐，莫负眼前光景也。", "(正末唱)咱人便休把时光虚度了，(蔡员外云)今日赏雪饮酒，都皆沉醉也。", "(正末唱)尽今生乐酶酶，饮香醪，满捧羊羔。", "宝鼎龙涎香未消，则他这银台上蜡烧。", "他每都觥筹欢笑，(旦儿云)蔡顺，今日父母十分欢喜也。", "(正末云)俺为子者，要孝当竭力也。", "(唱)则愿的一双父母寿年高。", "(同下)。"]'),
('yuanqu-7212','降桑椹蔡顺奉母・商调/集贤宾','刘唐卿','元','元曲','yuanqu','','[]','则俺那老萱亲在堂年迈高，小生我想恩养育痛悲号。',98,'元曲/yuanqu.json','["则俺那老萱亲在堂年迈高，小生我想恩养育痛悲号。", "俺母亲偎于湿三年乳哺，更怀耽十月劬劳。", "我母亲抬举的立志成名，生长的貌类清标。", "方信养生送死防备老，忆深恩我未报分毫。", "谁承望尊堂病已深，则俺这幼子泪如浇。"]'),
('yuanqu-7213','降桑椹蔡顺奉母・逍遥乐','刘唐卿','元','元曲','yuanqu','','[]','俺母亲骨岩岩身躯老耄，(带云)叹母亲这病，(唱)恰便似风里杨花，水亡幻泡。',149,'元曲/yuanqu.json','["俺母亲骨岩岩身躯老耄，(带云)叹母亲这病，(唱)恰便似风里杨花，水亡幻泡。", "(兴儿云)小哥不要心焦，到家里把奶奶的病，我替他害了罢。", "(正末唱)好教我便展转的添焦，俺母亲眼睁睁病枕难熬。", "我可便心似油煎身如火燎，仰穹苍痛哭嚎啕。", "(带云)蔡顺一片孝心，惟天可表也。", "(唱)则愿的母病安妥，父命延长，子寿愿夭。"]'),
('yuanqu-7214','降桑椹蔡顺奉母・南青哥儿','刘唐卿','元','元曲','yuanqu','','[]','入门来审了他这八脉，(糊突虫拿卜儿右手科)(唱)瘦伶仃有如麻秸。',121,'元曲/yuanqu.json','["入门来审了他这八脉，(糊突虫拿卜儿右手科)(唱)瘦伶仃有如麻秸。", "(太医唱)俺快把这药包儿忙解开。", "(糊突虫云)可怜也，脉息不好了。", "(唱)快疾忙去买，(太医唱)快疾忙占买。", "(正末云)太医，买甚么？(太医唱)去买一个棺材，(糊突虫唱)去买一个棺材。"]'),
('yuanqu-7215','降桑椹蔡顺奉母・后庭花','刘唐卿','元','元曲','yuanqu','','[]','我怎消的众神灵下紫霄，驾祥云香雾绕。',141,'元曲/yuanqu.json','["我怎消的众神灵下紫霄，驾祥云香雾绕。", "凛凛神威人，堂堂美像貌。", "赴天朝，亲传敕诏。", "为慈亲病重倒，因愚男尽孝道。", "后园中诚意祷，感天神来护保。", "枯桑上长出嫩条，香甘甘子结的饱。", "我摘将来盘内托，母亲行将孝意表，母亲行将孝意表。", "(增福神云)你那母亲，若食了这桑椹子，可自然病体安乐也。", "(正末唱)。"]'),
('yuanqu-7216','降桑椹蔡顺奉母・青哥儿','刘唐卿','元','元曲','yuanqu','','[]','吃了呵但能得尊堂、尊堂安乐，我做一坛水陆、水陆大醮。',129,'元曲/yuanqu.json','["吃了呵但能得尊堂、尊堂安乐，我做一坛水陆、水陆大醮。", "(增福神做推正末科，云)休推睡里梦里。", "(众神随下)(正末醒科)(唱)呀！原来是一枕南柯梦已觉。", "恰才那空中神道，与小生梦里相交，细说根苗，着我欢展眉梢。", "小生这些时耽着忧怀着闷受煎熬，恰才呵听说罢喜孜孜开怀抱。"]'),
('yuanqu-7217','降桑椹蔡顺奉母・尾声','刘唐卿','元','元曲','yuanqu','','[]','可又早飕飕的风力峭，惨惨的冻云罩。',96,'元曲/yuanqu.json','["可又早飕飕的风力峭，惨惨的冻云罩。", "他道是三更时分雪花飘，小生我深山中摘桑我可也不惮劳。", "怎敢把神灵违拗？(云)小生摘将那桑椹子来，母亲若吃下去呵。", "(唱)恰便是灵丹入腹可又早病儿消。", "(同旦儿下)。"]'),
('yuanqu-7218','降桑椹蔡顺奉母・中吕/粉蝶儿','刘唐卿','元','元曲','yuanqu','','[]','每日家腹内思量，则我这孝心肠岂能敢忘？忧的是老尊堂卧枕眠床。',76,'元曲/yuanqu.json','["每日家腹内思量，则我这孝心肠岂能敢忘？忧的是老尊堂卧枕眠床。", "我可便受驱驰，耽辛苦，满腹愁何曾展放？不由我心内忄西惶。", "俺母亲害的个病容颜，全不是旧时模样。"]'),
('yuanqu-7219','降桑椹蔡顺奉母・醉春风','刘唐卿','元','元曲','yuanqu','','[]','有一个董永卖亲身，黄香扇枕凉，郯子鹿乳奉萱堂。',55,'元曲/yuanqu.json','["有一个董永卖亲身，黄香扇枕凉，郯子鹿乳奉萱堂。", "这三人万代可便讲，讲。", "则愿的老母安康，病体健，町便是俺子孙兴旺。"]'),
('yuanqu-7220','降桑椹蔡顺奉母・迎仙客','刘唐卿','元','元曲','yuanqu','','[]','昨夜个瑞雪飘，雨汪洋，仰天外黑黯黯可便云雾长。',120,'元曲/yuanqu.json','["昨夜个瑞雪飘，雨汪洋，仰天外黑黯黯可便云雾长。", "融融的便暖如春，轰轰的便雷震响，影影的便电走金光，感应的祥瑞舞甘泽降。", "(兴儿云)小哥，你看这山林中，青山绿水，有如画意，堪入丹青之手也。", "(正末云)不觉的来到这大山中，是一派好山色景致也。", "(唱)。"]'),
('yuanqu-7221','降桑椹蔡顺奉母・红绣鞋','刘唐卿','元','元曲','yuanqu','','[]','看山色晴岚一样，看山峰高彻空苍，看山景叠翠蕊芬芳。',48,'元曲/yuanqu.json','["看山色晴岚一样，看山峰高彻空苍，看山景叠翠蕊芬芳。", "看山林难描画，看山涧水流长，端的是山中堪玩赏。"]'),
('yuanqu-7222','降桑椹蔡顺奉母・耍孩儿','刘唐卿','元','元曲','yuanqu','','[]','愿哥哥腰金衣紫为卿相，稳做着皇家栋梁。',171,'元曲/yuanqu.json','["愿哥哥腰金衣紫为卿相，稳做着皇家栋梁。", "三檐伞下气昂昂，保忠臣护国安邦。", "则愿的功高位至官一品，竭力芳名万载扬。", "非夸奖，博一个乌靴象简，五带罗裳。", "(延岑云)兄弟言者当也，我则今日星夜长行也。", "(兴儿做背砌末科，云)这个东西，定是我背着。", "我说老延，你就不与我个牛蹄儿吃？(延岑云)兄弟稳登前路，多多拜上父母也。", "(正末云)哥哥，您兄弟知道了也。", "(唱)。"]'),
('yuanqu-7223','降桑椹蔡顺奉母・尾声','刘唐卿','元','元曲','yuanqu','','[]','哥哥你说的是壮士言，到京师见帝王。',122,'元曲/yuanqu.json','["哥哥你说的是壮士言，到京师见帝王。", "则要你去邪归正为良将，治国安邦万人讲。", "(同下)(延岑云)兄弟去了也。", "则今日将手下众兄弟都散了，某星夜起程，往京师见圣人，走一遭去。", "则今日便索登程，促行装亲赴神京。", "若为官举荐蔡顺，俺两个享富贵青史标名。", "(同下)。"]'),
('yuanqu-7224','降桑椹蔡顺奉母・正宫/端正好','刘唐卿','元','元曲','yuanqu','','[]','想怀耽，生身意，我可也报不的老母驱驰。',41,'元曲/yuanqu.json','["想怀耽，生身意，我可也报不的老母驱驰。", "则我这孝心肠感动天和地，俺可便行孝道无邪伪。"]'),
('yuanqu-7225','降桑椹蔡顺奉母・滚绣球','刘唐卿','元','元曲','yuanqu','','[]','我焚香祭赛天，不觉的睡似痴，见一位增福神降临凡世。',96,'元曲/yuanqu.json','["我焚香祭赛天，不觉的睡似痴，见一位增福神降临凡世。", "他说道半夜间响一阵春雷，他道是纷纷雪乱飞，淙淙雨下的疾。", "两般儿委实奇异，我醒来时心内猜疑。", "到天明我走到山间下，谁承望园内开花结果肥，椹子皆垂。"]'),
('yuanqu-7226','降桑椹蔡顺奉母・倘秀才','刘唐卿','元','元曲','yuanqu','','[]','这桑椹子犹如蜜水，(卜儿云)孩儿也，我吃了他呵，正是如渴思浆，如热思凉也。',152,'元曲/yuanqu.json','["这桑椹子犹如蜜水，(卜儿云)孩儿也，我吃了他呵，正是如渴思浆，如热思凉也。", "(正末云)母亲，这桑椹子，休看的他轻也。", "(唱)他可便蒙雨露开花蕊。", "(卜儿云)将来，我吃几个。", "(兴儿云)你倒会吃也。", "(正末唱)母亲心内思想腹内饥。", "(卜儿云)孩儿也，我这病看看的好将来了也。", "(正末唱)好着我生欢悦，展愁眉，请街坊庆喜。"]'),
('yuanqu-7227','降桑椹蔡顺奉母・叨叨令','刘唐卿','元','元曲','yuanqu','','[]','母亲，也你似那旧时节脉息通胸胃；恰才无半霎，就把你灾除退；(卜儿云)孩儿也，多亏你行这等孝顺之心也。',196,'元曲/yuanqu.json','["母亲，也你似那旧时节脉息通胸胃；恰才无半霎，就把你灾除退；(卜儿云)孩儿也，多亏你行这等孝顺之心也。", "(正末唱)则我这孝心肠，感动天和地。", "则愿的母亲年高百岁身荣贵。", "兀的不喜欢杀也波哥，喜欢杀也波哥，俺一家儿办诚心酬谢天和地。", "(卜儿云)孩儿，我不问你别。", "这牛蹄、粳米，是那里来的？(正末云)母亲，您孩儿大山之中，遇着延岑哥哥来。", "(卜儿云)延岑？他不去郑州迭配牢城，他在山中做些甚么那？(正末唱)。"]'),
('yuanqu-7228','降桑椹蔡顺奉母・脱布衫','刘唐卿','元','元曲','yuanqu','','[]','他在那大山里落草为贼，领半垓人马围随。',64,'元曲/yuanqu.json','["他在那大山里落草为贼，领半垓人马围随。", "枪刀摆旗幡招展，狼虎般显耀威势。", "(卜儿云)他在山中落草为寇，你可怎生撞见他来？(正末唱)。"]'),
('yuanqu-7229','降桑椹蔡顺奉母・小梁州','刘唐卿','元','元曲','yuanqu','','[]','他把我拿到营中要整理，谁承望认的真实。',44,'元曲/yuanqu.json','["他把我拿到营中要整理，谁承望认的真实。", "从前已往说端的，他喜则喜今日会，他说道相见在山溪。"]'),
('yuanqu-7230','降桑椹蔡顺奉母・幺篇','刘唐卿','元','元曲','yuanqu','','[]','我说道母亲病体实难退，俺哥哥听说罢两泪双垂。',50,'元曲/yuanqu.json','["我说道母亲病体实难退，俺哥哥听说罢两泪双垂。", "他说道老母的恩，心中记，他将这牛蹄和粳米，奉老母病将息。"]'),
('yuanqu-7231','降桑椹蔡顺奉母・尾声','刘唐卿','元','元曲','yuanqu','','[]','传宣降诏非容易，整办行装不可迟。',65,'元曲/yuanqu.json','["传宣降诏非容易，整办行装不可迟。", "俺可便盼程途去得疾，到朝中文武齐。", "见圣人习礼仪，受官爵加重职，俺博一个衣紫腰金贺声喜。", "(同众下)。"]'),
('yuanqu-7232','降桑椹蔡顺奉母・双调/新水令','刘唐卿','元','元曲','yuanqu','','[]','圣明天子重英贤，选儒流武十两件。',46,'元曲/yuanqu.json','["圣明天子重英贤，选儒流武十两件。", "文官扶社稷，良将保山川。", "端的是万载流传，今日个排筵会没佳宴。"]'),
('yuanqu-7233','降桑椹蔡顺奉母・驻马听','刘唐卿','元','元曲','yuanqu','','[]','幼小轻年，腹内孤穷学问浅。',354,'元曲/yuanqu.json','["幼小轻年，腹内孤穷学问浅。", "(殿头官云)久闻贤士广览诗书，堪为辅弼之臣也。", "(正末唱)你不劳挂念，我是个白衣人怎到得玉阶前？(殿头官云)说贤士文胜颜回，孝越曾参也。", "(正末云)大人，小人怎敢比先贤古人也？(唱)鸾鸣胜似鹊声喧，凤飞比雁先腾远。", "我自言小生腹空虚，怎敢比高儒选？(殿头官云)蔡秀才，你与延岑厮见者。", "(二人做见科)(正末云)呀、呀，哥哥，受您兄弟两拜。", "(做拜科，云)您兄弟多亏哥哥，在圣人跟前举荐。", "若不是哥哥，小生焉能得到此也？(延岑云)不敢。", "虽是某举荐，况贤弟忠孝双全，名播于朝。", "据贤弟胸怀锦绣，口吐珠玑，乃翰林之魁首，堪可国家任用。", "今日峥嵘，方称贤弟之志也。", "(正末云)多谢了哥哥抬举也。", "(殿头官云)蔡秀才，当日你母亲不安，冬寒天气，思想桑椹子食用，你可怎生得桑椹子来？你说一遍，我试听者。", "(正末唱)。"]'),
('yuanqu-7234','降桑椹蔡顺奉母・雁儿落','刘唐卿','元','元曲','yuanqu','','[]','想当日萱亲疾病缠，他可便思绫锦当时见。',59,'元曲/yuanqu.json','["想当日萱亲疾病缠，他可便思绫锦当时见。", "小生我焚香祷上苍，一梦里神灵现。", "(殿头官云)你梦中见神灵，说甚么来？(正末唱)。"]'),
('yuanqu-7235','降桑椹蔡顺奉母・得胜令','刘唐卿','元','元曲','yuanqu','','[]','呀！他道是冬寒月变做春天，半夜里雪花舞雨涟涟。',66,'元曲/yuanqu.json','["呀！他道是冬寒月变做春天，半夜里雪花舞雨涟涟。", "枯桑上生棋子，我醒来时把梦圆。", "走到那山前，桑椹子都生遍。", "摘将来新鲜，俺母亲吃了体自然。"]'),
('yuanqu-7236','降桑椹蔡顺奉母・沽美酒','刘唐卿','元','元曲','yuanqu','','[]','感大恩重呵怜，招杰士纳英贤。',40,'元曲/yuanqu.json','["感大恩重呵怜，招杰士纳英贤。", "端的足德似尧汤千古传，万万载江山固坚，好收成谢冲天。"]'),
('yuanqu-7237','降桑椹蔡顺奉母・太平令','刘唐卿','元','元曲','yuanqu','','[]','四海内年年纳献，掌山河一统安然。',58,'元曲/yuanqu.json','["四海内年年纳献，掌山河一统安然。", "万回来偏邦朝见，文共武随龙迁转。", "呀，谢圣恩可怜，就传将俺来便宣，一一的拜舞金銮宝殿。"]'),
('yuanqu-7238','双调・寿阳曲思旧','邦哲','元','元曲','yuanqu','','[]','初相见，意思浓，两下爱衾枕和同。',99,'元曲/yuanqu.json','["初相见，意思浓，两下爱衾枕和同。", "销金帐春色溶溶，云雨期真叠叠重重。", "谁知道，天不容，两三年间抛鸾拆凤。", "苦多情朝思夜梦，害相思沉沉病重。", "尔在东，我在西，阳台梦隔断山溪。", "孤雁唳夜半月凄凄，再相逢此生莫期。"]'),
('yuanqu-7239','龙济山野猿听经・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','空学得五典皆通，九经皆诵，成何用。',33,'元曲/yuanqu.json','["空学得五典皆通，九经皆诵，成何用。", "铲的将儒业参攻，受了十载寒窗冷。"]'),
('yuanqu-7240','龙济山野猿听经・油葫芦','无名氏','元','元曲','yuanqu','','[]','想着那颜子箪瓢陋巷中，孟子便穷通是儒道宗，养浩然只恁般气冲冲。',91,'元曲/yuanqu.json','["想着那颜子箪瓢陋巷中，孟子便穷通是儒道宗，养浩然只恁般气冲冲。", "想着那车书一统山河共，却怎生衣冠不许儒人共。", "聪明的久困在闲，愚蠢的爵禄封。", "自俺那寒窗风雪十年冻，不知俺受贫的却也甚日荣。"]'),
('yuanqu-7241','龙济山野猿听经・醉扶归','无名氏','元','元曲','yuanqu','','[]','只见那山顶依仙洞，涧底隐蛟龙。',52,'元曲/yuanqu.json','["只见那山顶依仙洞，涧底隐蛟龙。", "胜似巫山十二重，五彩般祥云涌。", "堪可与仙家受用，既不是者波却怎岭外飞着双凤。"]'),
('yuanqu-7242','龙济山野猿听经・村里迓鼓','无名氏','元','元曲','yuanqu','','[]','我子见碧霄、碧霄云控，绿岩、绿岩畔风动。',79,'元曲/yuanqu.json','["我子见碧霄、碧霄云控，绿岩、绿岩畔风动。", "有他那苍松古柏，见一派寒泉出迸。", "你看那桃花喷火，杨柳拖烟，依稀庵洞。", "更有那鹳鸟呜，芝兰秀，桂柏荣，呀，妆点的清幽寺拥。"]'),
('yuanqu-7243','龙济山野猿听经・元和令','无名氏','元','元曲','yuanqu','','[]','大雄殿瑞霭浓，禅堂外晓烟重。',48,'元曲/yuanqu.json','["大雄殿瑞霭浓，禅堂外晓烟重。", "我只见那和风丽日春正浓，花柳鲜百样同。", "山茶吐锦曲阑中，散一阵暖香风。"]'),
('yuanqu-7244','龙济山野猿听经・上马娇','无名氏','元','元曲','yuanqu','','[]','阶边又花影重，林前又桃蕊红。',44,'元曲/yuanqu.json','["阶边又花影重，林前又桃蕊红。", "山共水四围中，我只见奇峰峻岭高低耸。", "道苑又重丛，春色花暗融。"]'),
('yuanqu-7245','龙济山野猿听经・后庭花','无名氏','元','元曲','yuanqu','','[]','我只见直云霓仰大空，更和这接苍虚叨利宫。',62,'元曲/yuanqu.json','["我只见直云霓仰大空，更和这接苍虚叨利宫。", "缥缈烟笼柳，飘摇风撼着松。", "我只见遍西东，悠然如梦。", "怎如俺步青霄三岛峰，玩名山千万重。"]'),
('yuanqu-7246','龙济山野猿听经・柳叶儿','无名氏','元','元曲','yuanqu','','[]','感谢尊师相陪奉，拜禅林礼义谦恭，我凡夫得遇蓬莱洞。',41,'元曲/yuanqu.json','["感谢尊师相陪奉，拜禅林礼义谦恭，我凡夫得遇蓬莱洞。", "我这里，意匆匆，拜别了重下云峰。"]'),
('yuanqu-7247','龙济山野猿听经・尾声','无名氏','元','元曲','yuanqu','','[]','我自索下山峰，离仙洞，再入径绕绕红尘道中。',98,'元曲/yuanqu.json','["我自索下山峰，离仙洞，再入径绕绕红尘道中。", "我将这胜迹观绝意气融，过奇山异水叠重。", "索强似五云峰，更胜似岱岳巅峰，回首白云千道冲。", "不必比俺阎浮世界中，堪可与天宫相纵，却正是梵王亲建一座紫霄宫。", "(下)。"]'),
('yuanqu-7248','龙济山野猿听经・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','赤力力轻攀地府欹，束刺刺紧拨天关落。',69,'元曲/yuanqu.json','["赤力力轻攀地府欹，束刺刺紧拨天关落。", "推斜华岳顶，扯倒玉峰腰。", "怒时节海浪洪涛，闲时把江湖搅，向山林行了一遭。", "显神通变化多般，施勇跃心灵性巧。"]'),
('yuanqu-7249','龙济山野猿听经・梁州第七','无名氏','元','元曲','yuanqu','','[]','我恰才向寒泉间乘凉洗濯，早来到九皋峰戏耍咆哮。',171,'元曲/yuanqu.json','["我恰才向寒泉间乘凉洗濯，早来到九皋峰戏耍咆哮。", "我将这苍松树上身轻跳。", "我却便拈枝弄叶，摘干搬条，垂悬着手脚，挂倒着身腰。", "一番身千丈低高，片时间万里途遥。", "我、我、我，也曾在瑶池内偷饮了琼浆，我、我、我，也曾在蓬莱山偷摘了瑞草，我、我、我，也曾在天宫内闹了蟠桃。", "神通，不小。", "只为我肠中有不老长生药，呼风雨逞威要。", "我在林下山前走几遭，常好是乐意逍遥。"]'),
('yuanqu-7250','龙济山野猿听经・隔尾','无名氏','元','元曲','yuanqu','','[]','我这里将帚尘不住在阶址扫，忙将这铙钹手内敲。',214,'元曲/yuanqu.json','["我这里将帚尘不住在阶址扫，忙将这铙钹手内敲。", "只听得树叶响嘶零零，我只怕行人到。", "好着我左瞧，右瞧，原来是风摆动檐头殿铃索。", "(云)上的禅床，我坐一坐咱。", "(禅师上，云)贫僧方才在后山中禅堂入定，猛听得佛殿内不知是何人在此游玩。", "我试向佛殿门前，看是甚的。", "呵、呵、呵，原来是个玄猿，在此作戏。", "我且不觑破他，只在此看他怎生作戏。", "(正末云)我下的禅床来呵。", "那壁供桌上放着物件，我自看去。", "(禅师云)他元来在此这般作戏也，我是再看咱。", "(正末唱)。"]'),
('yuanqu-7251','龙济山野猿听经・牧羊关','无名氏','元','元曲','yuanqu','','[]','我将这经文从头念，袈裟身上穿，把幡幡伞盖拿着。',73,'元曲/yuanqu.json','["我将这经文从头念，袈裟身上穿，把幡幡伞盖拿着。", "饮了些胆瓶中净水馨香，嗅了些瓦鼎内沉檀缥缈。", "我这里上侧畔蒲团倒，近经案吹笙箫，我这里转身跳跃观觑了。"]'),
('yuanqu-7252','龙济山野猿听经・采茶歌','无名氏','元','元曲','yuanqu','','[]','告尊神且担饶，吓得我五魂消，再不敢僧房佛殿逞逍遥。',48,'元曲/yuanqu.json','["告尊神且担饶，吓得我五魂消，再不敢僧房佛殿逞逍遥。", "将我这性命登时间杀坏了，怎能勾瑶池献果到青霄。"]'),
('yuanqu-7253','龙济山野猿听经・尾声','无名氏','元','元曲','yuanqu','','[]','再不敢身登山岭逍遥乐，来向禅堂闲戏跃。',58,'元曲/yuanqu.json','["再不敢身登山岭逍遥乐，来向禅堂闲戏跃。", "我自去洞里深藏理玄妙，把灵光悟晓，将经文听了，修一个般若心便是正果了。", "(下)。"]'),
('yuanqu-7254','龙济山野猿听经・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','见了些尘世荣华，羡功名一场风化。',62,'元曲/yuanqu.json','["见了些尘世荣华，羡功名一场风化。", "看他每闹垓垓斗逞奢华，每日家插宫花，斟御酒，常只是胸襟宽大。", "名利交加，到如今都做了渔樵闲话。"]'),
('yuanqu-7255','龙济山野猿听经・醉春风','无名氏','元','元曲','yuanqu','','[]','经了些翻滚滚恶尘途，受了些急穰穰世事杂。',90,'元曲/yuanqu.json','["经了些翻滚滚恶尘途，受了些急穰穰世事杂。", "想着那人生否泰在须臾，敢不是假，假。", "利锁名缰，居官受禄，到如今都一笔勾罢。", "(云)小生来到这座山中，看了这座山，比与他山甚是不同也呵！(唱)。"]'),
('yuanqu-7256','龙济山野猿听经・红绣鞋','无名氏','元','元曲','yuanqu','','[]','一缕游云直下，半泓秋水交加，有他那苍松丛内鸟音杂。',50,'元曲/yuanqu.json','["一缕游云直下，半泓秋水交加，有他那苍松丛内鸟音杂。", "一壁厢烟笼树，一壁厢雾侵霞，恰便似小蓬莱移在这榻。"]'),
('yuanqu-7257','龙济山野猿听经・石榴花','无名氏','元','元曲','yuanqu','','[]','太师一一问根芽，小生也曾得志贯京华。',79,'元曲/yuanqu.json','["太师一一问根芽，小生也曾得志贯京华。", "不图富贵显撑达，只恐怕违条犯法，因此上隐迹归家。", "乐云山散诞无牵挂，抵多少年八十弛步烟霞。", "虽居陋巷心无挂。", "便是那一世拙生涯。"]'),
('yuanqu-7258','龙济山野猿听经・斗鹌鹑','无名氏','元','元曲','yuanqu','','[]','想咱人尘世荣华，却便似朝霜暮霞。',133,'元曲/yuanqu.json','["想咱人尘世荣华，却便似朝霜暮霞。", "空学星斗文章，逃不出萧何律法。", "今古兴亡可鉴察，小生也不恋那。", "我无意为官，无福受高车驷马。", "(禅师云)先生。", "岂不闻为官者，打一轮皂盖，列两行朱衣，亲戚称羡，乡党宾服，比那出家，较是不同也。", "(正末云)太师，你那里知道小生的心事也呵！(唱)。"]'),
('yuanqu-7259','龙济山野猿听经・满庭芳','无名氏','元','元曲','yuanqu','','[]','我宁可衣冠不加，我乐的是山林清趣，我再不告蝶阵蜂衙。',152,'元曲/yuanqu.json','["我宁可衣冠不加，我乐的是山林清趣，我再不告蝶阵蜂衙。", "将心猿意马都拴罢，弃却了玉锁金枷。", "怕的是红尘混杂，愁的是业海交加。", "隐遁在桑田下，向白云那塌，小生乐道出河沙。", "(禅师云)先生的意，贫僧尽知了也。", "先生，争奈你若顶巾束发，在我教谓之沐猴而冠；若使削发披缁，在公教谓之儒名墨行。", "若斯二者，何以处之？(正末唱)。"]'),
('yuanqu-7260','龙济山野猿听经・上小楼','无名氏','元','元曲','yuanqu','','[]','太师道衣冠不佳，你教我皈依削发。',108,'元曲/yuanqu.json','["太师道衣冠不佳，你教我皈依削发。", "却不道心本元明，色相皆空无点差。", "只待要念经文，参话头，尘缘弃下，便是那礼禅帅永无牵挂。", "(禅师云)先生既是如此，却也可也。", "既临此庵，且向山中游玩一回咱。", "(正末云)是一座好山也呵！(唱)。"]'),
('yuanqu-7261','龙济山野猿听经・耍孩儿','无名氏','元','元曲','yuanqu','','[]','恰便似青螺放顶云霄中插，高接凌空彩霞。',76,'元曲/yuanqu.json','["恰便似青螺放顶云霄中插，高接凌空彩霞。", "你看俺奇山秀水两交加，绕僧堂禅室堪佳。", "果然是依为佛祖菩提处。", "堪作禅僧寂静家。", "端的是真图画，小生心响豁畅，肺腑清嘉。"]'),
('yuanqu-7262','龙济山野猿听经・尾声','无名氏','元','元曲','yuanqu','','[]','谁想我火宅中一跳身，洪涛中出海涯。',44,'元曲/yuanqu.json','["谁想我火宅中一跳身，洪涛中出海涯。", "我宁个寺中拜礼如来塔，我只待悟三教真如大藏法。", "(下)。"]'),
('yuanqu-7263','龙济山野猿听经・仙吕/赏花时','无名氏','元','元曲','yuanqu','','[]','到来日亲赴禅堂来听讲，参悟如来般若乡。',49,'元曲/yuanqu.json','["到来日亲赴禅堂来听讲，参悟如来般若乡。", "小生剪画烛炷明香，礼拜尊师法王，我却便求接引入天堂。", "(下)。"]'),
('yuanqu-7264','龙济山野猿听经・双调/新水令','无名氏','元','元曲','yuanqu','','[]','今日一心参透祖师禅，我将这大圆明片时间发见。',46,'元曲/yuanqu.json','["今日一心参透祖师禅，我将这大圆明片时间发见。", "灵台无污染，丹府绝尘缠。", "本性大然，真如相悟当面。"]'),
('yuanqu-7265','龙济山野猿听经・驻马听','无名氏','元','元曲','yuanqu','','[]','师父你道德渊深，亲传妙理会人大。',66,'元曲/yuanqu.json','["师父你道德渊深，亲传妙理会人大。", "禅机应变，果然是十方贤圣仰师颜。", "这的法佛是僧保俚真诠，惟心奥意当时展。", "不可言，真乃是西天佛祖亲身现。"]'),
('yuanqu-7266','龙济山野猿听经・沉醉东风','无名氏','元','元曲','yuanqu','','[]','妙理俄然便显，心如五叶清清。',47,'元曲/yuanqu.json','["妙理俄然便显，心如五叶清清。", "将他这色相来灵光现，似一潭秋水澄渊。", "体自如如不用言，便是如来教典。"]'),
('yuanqu-7267','龙济山野猿听经・沽美酒','无名氏','元','元曲','yuanqu','','[]','我则见降霞飘五彩鳞，庆云生半空见，有他那宝树奇花满殿前。',42,'元曲/yuanqu.json','["我则见降霞飘五彩鳞，庆云生半空见，有他那宝树奇花满殿前。", "更有这莲池碧莲，真个罕曾见。"]'),
('yuanqu-7268','龙济山野猿听经・太平令','无名氏','元','元曲','yuanqu','','[]','恰便是九重阙蓬莱宫殿，五云乡紫气攸然。',55,'元曲/yuanqu.json','["恰便是九重阙蓬莱宫殿，五云乡紫气攸然。", "动仙音清霄普遍，列幢幡飘摇皆现。", "也是俺，有缘，遇善缘，贺飞腾入普陀天院。"]'),
('yuanqu-7269','龙济山野猿听经・折桂令','无名氏','元','元曲','yuanqu','','[]','师父道登西方九品莲池，都只为悟彻无生，今日个平步上青天。',272,'元曲/yuanqu.json','["师父道登西方九品莲池，都只为悟彻无生，今日个平步上青天。", "再不去那山内闻经，林头抱影，涧底吟泉。", "我今日脱皮囊凡胎尽传，上灵山佛国攸然。", "也是苦志心坚，稳驾清风，飞上青天。", "(圣僧云)袁生，此间已是西方极乐世界。", "只因你一心向善，问道修真，致有今日。", "你看祥云霭霭，紫气腾腾，慈悲接引，善信偕行，果然是步步踏金莲也。", "袁生，你听者！只因你一念真心，悟如来般若玄音。", "脱皮毛闻经听法，改形容参访师林。", "了然彻无生道妙，须明透万法洪深。", "除却了轮回六道，免去了苦海潜津。", "赴西方莲开见佛，临极乐亲到雷音。", "今日个成真证果，礼如来法座皆钦。", "(正末云)也是我有缘也呵！(唱)。"]'),
('yuanqu-7270','龙济山野猿听经・殿前欢','无名氏','元','元曲','yuanqu','','[]','今日个得升天，悟真如性海道心虔。',68,'元曲/yuanqu.json','["今日个得升天，悟真如性海道心虔。", "祥云影里真佛现，拜礼慈颜。", "显祥光万道传，绚瑞彩千条现，散天花云端中见。", "果然是人间少有，世界难全。", "(下)。"]'),
('yuanqu-7271','越调・斗鹌鹑题情','赵明道','元','元曲','yuanqu','','[]','燕燕莺莺，花花草草。',55,'元曲/yuanqu.json','["燕燕莺莺，花花草草。", "穰穰劳劳，多多少少。", "媚媚娇娇，亭亭袅袅。", "鸾凤交，没下梢。", "空耽了些是是非非，受了些烦烦恼恼。"]'),
('yuanqu-7272','紫花儿・困腾腾头昏脑闷，急煎煎意穰心劳，虚飘飘魄散魂消。他风风韵','赵明道','元','元曲','yuanqu','','[]','韵，艳艳夭夭。',42,'元曲/yuanqu.json','["韵，艳艳夭夭。", "日日朝朝，雨雨云云渐缥渺，那堪暮秋天道。", "似这般爽气清高，那堪夜雨萧萧。"]'),
('yuanqu-7273','秃厮儿・闷厌厌愁心怎熬，昏沉沉梦断魂劳。秋声和辘轳砧韵敲，淅零零','赵明道','元','元曲','yuanqu','','[]','细雨洒芭蕉，初凋。',9,'元曲/yuanqu.json','["细雨洒芭蕉，初凋。"]'),
('yuanqu-7274','小桃红・枕寒衾冷夜迢迢，旖旎人儿俏，往往难成梦惊觉。好心焦，悲悲','赵明道','元','元曲','yuanqu','','[]','切切雁儿呀呀的叫。',36,'元曲/yuanqu.json','["切切雁儿呀呀的叫。", "透户牖，金风淅淅，滴更长，铜壶点点，更那堪蛩韵絮叨叨。"]'),
('yuanqu-7275','天净沙・厌厌鬼病难消，凄凄心痒难揉，渐渐神魂散却。好教人没颠没倒，','赵明道','元','元曲','yuanqu','','[]','意迟迟业眼难交。',8,'元曲/yuanqu.json','["意迟迟业眼难交。"]'),
('yuanqu-7276','紫花儿・雷声声梁苑，禾惜惜都城，苏小小钱塘。三人声价，四海名扬。','赵明道','元','元曲','yuanqu','','[]','红妆，忒旖旎忒风流忒四行，堪写在宣和图上。',35,'元曲/yuanqu.json','["红妆，忒旖旎忒风流忒四行，堪写在宣和图上。", "有百倍儿风标，无半米儿疏狂。"]'),
('yuanqu-7277','秃厮儿・为媒的涿郡仲襄，保亲的苏君丘祥。青春二八年正芳，配一对锦','赵明道','元','元曲','yuanqu','','[]','鸳鸯，成双。',6,'元曲/yuanqu.json','["鸳鸯，成双。"]'),
('yuanqu-7278','圣药王・我岂谎，您诚想，苏小卿到底嫁双郎，因为和乐章，动官长。柳','赵明道','元','元曲','yuanqu','','[]','耆卿娶了谢天香，他知音律解宫商。',16,'元曲/yuanqu.json','["耆卿娶了谢天香，他知音律解宫商。"]'),
('yuanqu-7279','尾・郝大使王玉带皆称赏，焦治中天然秀小样。劝你个聪明姝丽俏吴姬，','赵明道','元','元曲','yuanqu','','[]','就取这蕴藉风流俊张敞。',11,'元曲/yuanqu.json','["就取这蕴藉风流俊张敞。"]'),
('yuanqu-7280','双调・夜行船寄香罗帕','赵明道','元','元曲','yuanqu','','[]','多绪多情意似痴，闲愁闷禁持。',31,'元曲/yuanqu.json','["多绪多情意似痴，闲愁闷禁持。", "心绪熬煎，形容憔悴，又添这场萦系。"]'),
('yuanqu-7281','步步娇・一幅香罗他亲寄，寄与咱别无意。他教咱行坐里，行坐里和他不','赵明道','元','元曲','yuanqu','','[]','相离。',17,'元曲/yuanqu.json','["相离。", "若是恁还知，淹了多少关山泪。"]'),
('yuanqu-7282','沉醉东风・鹿顶盒儿最喜，羊脂玉纳子偏宜。挑成祝寿词，织成蟠桃会，','赵明道','元','元曲','yuanqu','','[]','吴绫蜀锦难及。',23,'元曲/yuanqu.json','["吴绫蜀锦难及。", "幅尺阔全无半缕纰，密实十分奈洗。"]'),
('yuanqu-7283','拨不断・旧痕积，泪淋漓，越点污越香气。沉醉后堪将口上吸，更忙呵休','赵明道','元','元曲','yuanqu','','[]','向腰间系，怕显出这场恩义。',13,'元曲/yuanqu.json','["向腰间系，怕显出这场恩义。"]'),
('yuanqu-7284','离亭煞・用工夫度线金针刺，无包弹捻锹银丝细。气命儿般敬重看承，心','赵明道','元','元曲','yuanqu','','[]','肝儿般爱怜收拾，止不过包胆茶胧罗笠，就不尽千般旖旎。',41,'元曲/yuanqu.json','["肝儿般爱怜收拾，止不过包胆茶胧罗笠，就不尽千般旖旎。", "忙扌若在手儿中，荒笼在袖儿里。"]'),
('yuanqu-7285','张孔目智勘魔合罗・仙吕/赏花时','孟汉卿','元','元曲','yuanqu','','[]','则为你叔嫂从来情性乖，我因此上将伊曾劝解。',86,'元曲/yuanqu.json','["则为你叔嫂从来情性乖，我因此上将伊曾劝解。", "(旦悲科，云)你去了，我怎了也！(正未唱)你可便省烦恼，莫伤怀。", "你则照管这家私世外，(带云)别的不打紧。", "(唱)你是必好觑当小婴孩。"]'),
('yuanqu-7286','张孔目智勘魔合罗・幺篇','孟汉卿','元','元曲','yuanqu','','[]','则俺这男子为人须挣坐，我向这外府他乡做买卖。',68,'元曲/yuanqu.json','["则俺这男子为人须挣坐，我向这外府他乡做买卖。", "(旦云)你则是早些回来。", "(正末唱)休则管泪盈腮，多不到一年半载，但得些利便回来。", "(同旦下)。"]'),
('yuanqu-7287','张孔目智勘魔合罗・仙吕/点绛唇','孟汉卿','元','元曲','yuanqu','','[]','七月才初，孟秋时序，犹存暑。',30,'元曲/yuanqu.json','["七月才初，孟秋时序，犹存暑。", "穿着这单布衣服，怎避这悬麻雨？。"]'),
('yuanqu-7288','张孔目智勘魔合罗・混江龙','孟汉卿','元','元曲','yuanqu','','[]','连阴不住，荒郊一望水模糊。',93,'元曲/yuanqu.json','["连阴不住，荒郊一望水模糊。", "我则见雨迷了山岫，云锁了青虚。", "(带云)这雨大不大？(唱)云气深，如倒悬着东大海；雨势大，似翻合了洞庭湖。", "好教我满眼儿没处寻归路，黑暗暗云迷四野，白茫茫水淹长涂。"]'),
('yuanqu-7289','张孔目智勘魔合罗・油葫芦','孟汉卿','元','元曲','yuanqu','','[]','恰便似画出潇湘水墨图，淋的我湿渌渌，更那堪吉丢古堆波浪渲城渠。',109,'元曲/yuanqu.json','["恰便似画出潇湘水墨图，淋的我湿渌渌，更那堪吉丢古堆波浪渲城渠。", "你看他吸留忽刺水流乞留曲律路，更和这失留疏剌风摆希留急了树。", "怎当他乞纽忽浓的泥，更和他匹丢扑搭的淤。", "我与你便急章拘诸慢行的赤留出律去，我则索滴羞跌屑整身躯。"]'),
('yuanqu-7290','张孔目智勘魔合罗・醉扶归','孟汉卿','元','元曲','yuanqu','','[]','我这里扭我这单布裤，晒我这湿衣服。',149,'元曲/yuanqu.json','["我这里扭我这单布裤，晒我这湿衣服。", "(云)怎生这般漏？哦！元来是这屋宇坍塌了，所以这般漏。", "我试看这行李咱。", "(唱)我则怕盖行李的油单有漏处，我与你须索从头觑。", "(云)且喜得都不曾湿嗨！可怎生这等漏得紧。", "(唱)奇怪这两三番揩不干我这额头颅，(云)可是为甚么？呆汉，你慌怎的？(唱)可忘了将我这湿渌渌头巾去。"]'),
('yuanqu-7291','张孔目智勘魔合罗・后庭花','孟汉卿','元','元曲','yuanqu','','[]','俺家里有一遭新板闼住两间高瓦屋。',64,'元曲/yuanqu.json','["俺家里有一遭新板闼住两间高瓦屋。", "隔壁儿是个熟食店，对门儿是个生药局。", "怕老的若有不是处你则问那里是李德昌家绒线铺，街坊每他都道与。"]'),
('yuanqu-7292','张孔目智勘魔合罗・赚煞','孟汉卿','元','元曲','yuanqu','','[]','你是必记心怀，你叮也休疑虑，不是我嘱咐了重还嘱咐。',93,'元曲/yuanqu.json','["你是必记心怀，你叮也休疑虑，不是我嘱咐了重还嘱咐。", "争奈自己耽疾难动举，你教他借马寻驴莫踌躇。", "争奈纸笔全无，怎写旷安两字书？老的只要你莫阻，说与俺看家拙妇，教他早些来把我这病人扶。", "(下)。"]'),
('yuanqu-7293','张孔目智勘魔合罗・黄钟/醉花阴','孟汉卿','元','元曲','yuanqu','','[]','干着我贩卖南昌利钱好，急叫来又早病魔缠着。',69,'元曲/yuanqu.json','["干着我贩卖南昌利钱好，急叫来又早病魔缠着。", "盼家门咫尺似天遥，好教我这会儿心焦，按不住小鹿儿拘拘地跳。", "端的是最难熬，只一阵头疼险些就劈破了。"]'),
('yuanqu-7294','张孔目智勘魔合罗・喜迁莺','孟汉卿','元','元曲','yuanqu','','[]','教谁来医疗，奈无人古庙萧萧。',58,'元曲/yuanqu.json','["教谁来医疗，奈无人古庙萧萧。", "量度，又怕有歹人来到。", "不由人小中添懊恼，不由人不泪雨抛。", "迭屑屑魂飞胆落，扑速速肉颤身摇。"]'),
('yuanqu-7295','张孔目智勘魔合罗・出队子','孟汉卿','元','元曲','yuanqu','','[]','似这般无颠无倒，越趣人厮窨约。',51,'元曲/yuanqu.json','["似这般无颠无倒，越趣人厮窨约。", "一会家阴阴的腹痛似锥挑，一会家烘烘的发热似火烧，一会家撒撒的增寒似水浇。"]'),
('yuanqu-7296','张孔目智勘魔合罗・刮地风','孟汉卿','元','元曲','yuanqu','','[]','悬望妻儿音信杳，急煎煎心痒难揉。',108,'元曲/yuanqu.json','["悬望妻儿音信杳，急煎煎心痒难揉。", "(云)我出庙门望一望波。", "(唱)我这里慢腾腾行出灵神庙，举日偷瞧。", "我与你恰下涩道，立在檐梢，觉昏沉刚挣揣把门倚靠。", "我则道十分紧闭着，原来是不插拴牢。", "靠着时呀的门开了，滴留扑仰剌叉吃一交。"]'),
('yuanqu-7297','张孔目智勘魔合罗・四门子','孟汉卿','元','元曲','yuanqu','','[]','这的是严霜偏打枯根草，哎哟！正跌着我这残病腰。',88,'元曲/yuanqu.json','["这的是严霜偏打枯根草，哎哟！正跌着我这残病腰。", "一会家疼一会家焦，想钱财莫不是无福消？一会家疼一会家焦，我将这神灵祷告。", "(李文道慌上)来到这庙也，哥哥在那里？(正末见科)(唱)。"]'),
('yuanqu-7298','张孔目智勘魔合罗・古水仙子','孟汉卿','元','元曲','yuanqu','','[]','呀、呀、呀，猛见了，嗨、嗨、嗨，唬的我悠悠魂魄消。',144,'元曲/yuanqu.json','["呀、呀、呀，猛见了，嗨、嗨、嗨，唬的我悠悠魂魄消。", "将、将、将，纸钱来忙遮，把、把、把，泥神来紧靠，慌、慌、慌，我这驻掩映着。", "(李文道云)我来望哥哥，受你兄弟两拜。", "(正末唱)他、他、他，走将来展脚舒腰，我、我、我，向前来仔细观了相貌。", "是、是、是，我兄弟间别身安乐，请、请、清，免拜波李文道。"]'),
('yuanqu-7299','张孔目智勘魔合罗・寨儿令','孟汉卿','元','元曲','yuanqu','','[]','也不昨宵，则是今朝，被风寒暑湿吹着。',160,'元曲/yuanqu.json','["也不昨宵，则是今朝，被风寒暑湿吹着。", "(李文道云)我与哥哥把把脉咱。", "(做把脉科，云)哥哥，我知道这病也，我就带将药来了。", "(做调药，与正末吃科)(正末云)兄弟且住，等你嫂嫂来我吃。", "(李文道云)不要等他，你吃了就好了。", "(正末咽科)(唱)我咽下去有似热油浇，烘烘的烧五脏，火火的燎三焦。", "(带云)兄弟也，(唱)这的敢不是风寒药？。"]'),
('yuanqu-7300','张孔目智勘魔合罗・神仗儿','孟汉卿','元','元曲','yuanqu','','[]','他将那水凋，我氵虢的咽了，不觉忽的昏迷，他把我丕的来药倒。',54,'元曲/yuanqu.json','["他将那水凋，我氵虢的咽了，不觉忽的昏迷，他把我丕的来药倒。", "烟生七窍，冰浸四稍。", "谁承望笑里藏刀，眼见的丧荒郊。"]'),
('yuanqu-7301','张孔目智勘魔合罗・节节高','孟汉卿','元','元曲','yuanqu','','[]','这厮如损人利己，不合大道。',55,'元曲/yuanqu.json','["这厮如损人利己，不合大道。", "钱物又不多，要时分明要，怎生下得教哥哥身夭。", "更做道钱心重，情分少，任辱没杀分金管鲍。"]'),
('yuanqu-7302','张孔目智勘魔合罗・者刺古','孟汉卿','元','元曲','yuanqu','','[]','身躯被病执缚，难走难逃。',58,'元曲/yuanqu.json','["身躯被病执缚，难走难逃。", "咽喉被药把捉，难叫难号。", "托青天暗表，望灵神早报。", "行善得善，行恶得恶。", "天呵！莫不是今年灾祸招。"]'),
('yuanqu-7303','张孔目智勘魔合罗・挂金索','孟汉卿','元','元曲','yuanqu','','[]','我则道调理风寒，谁想他暗里藏毒药。',59,'元曲/yuanqu.json','["我则道调理风寒，谁想他暗里藏毒药。", "他如今致命图财，我正是自养着家生哨，疑怪来时，不将着亲嫂嫂。", "万代人传，倒惹的关张笑。"]'),
('yuanqu-7304','张孔目智勘魔合罗・尾','孟汉卿','元','元曲','yuanqu','','[]','所有金珠共财宝，一星星早不剩分毫，他紧紧的将马儿驮去了。',28,'元曲/yuanqu.json','["所有金珠共财宝，一星星早不剩分毫，他紧紧的将马儿驮去了。"]'),
('yuanqu-7305','张孔目智勘魔合罗・商调/集贤宾','孟汉卿','元','元曲','yuanqu','','[]','这些时曹司里有些勾当，我这里因佥押离了司房。',99,'元曲/yuanqu.json','["这些时曹司里有些勾当，我这里因佥押离了司房。", "我如今身耽受公私利害，笔尖注生死存亡。", "详察这生分女作歹为非，更和这忤逆男随波逐浪。", "我可又奉官人委付将六案掌，有公事怎敢仓皇。", "则听的冬冬传击鼓，偌偌报撺箱。"]'),
('yuanqu-7306','张孔目智勘魔合罗・逍遥乐','孟汉卿','元','元曲','yuanqu','','[]','我则抬头观望，官长升厅，静悄悄有如听讲。',78,'元曲/yuanqu.json','["我则抬头观望，官长升厅，静悄悄有如听讲。", "我索整顿了衣裳，正行中举目参详。", "见雄纠纠公人如虎狼，推拥着个得罪的婆娘。", "则见他愁眉泪眼，带锁披枷，莫不是竞土争桑？。"]'),
('yuanqu-7307','张孔目智勘魔合罗・金菊香','孟汉卿','元','元曲','yuanqu','','[]','我则见湿浸浸血污了旧衣裳，多应是碜可可的身耽着新棒疮，更那堪死囚枷压伏的驼了脊梁。',56,'元曲/yuanqu.json','["我则见湿浸浸血污了旧衣裳，多应是碜可可的身耽着新棒疮，更那堪死囚枷压伏的驼了脊梁。", "他把这粉颈舒长，伤心处泪汪汪。"]'),
('yuanqu-7308','张孔目智勘魔合罗・醋葫芦','孟汉卿','元','元曲','yuanqu','','[]','我孜孜的觑了一会，明明的观了半晌，我见他不平中把心事暗包藏。',64,'元曲/yuanqu.json','["我孜孜的觑了一会，明明的观了半晌，我见他不平中把心事暗包藏。", "婆娘家怎生遭这般冤屈纲，偏惹得带枷吃棒，休、休、休道不的自己枉着忙。"]'),
('yuanqu-7309','张孔目智勘魔合罗・幺篇','孟汉卿','元','元曲','yuanqu','','[]','我这里慢慢的转过两廊，迟迟的行至禀堂。',454,'元曲/yuanqu.json','["我这里慢慢的转过两廊，迟迟的行至禀堂。", "他那里哭啼啼口内诉衷肠，我待两三番推阻不问当。", "(张千云)刘玉娘，你告这个孔目哥哥，他与你做主。", "(旦扯住正末衣科，云)哥哥救我咱。", "(正末唱)他紧拽定衣服不放，不由咱不与你做商量。", "(云)张千，把那妇人唤至跟前，我问他。", "(张千云)刘玉娘近前来。", "(旦跪科)(正末云)兀那妇人，说你那词因我听咱。", "(旦诉词，云)哥哥停嗔息怒，听妾身从头分诉。", "李德昌本为躲灾，贩南昌多有钱物。", "他来到庙中困歇，不承望感的病促。", "到家中七窍内迸流鲜血，知他是怎生服毒。", "进入门当下身亡，慌的我去叫小叔叔。", "他道我暗地里养着奸夫，将毒药药的亲夫身故。", "不明白拖到官司，吃棍棒打拷无数。", "我是个妇人家怎熬这六问三推，葫芦提屈画了招状。", "我须是李德昌绾角儿夫妻，怎下的胡行乱做。", "小叔叔李文道暗使计谋，我委实的衔冤负屈。", "(正末云)兀那妇人，我替你相公行说去。", "说准呵你休欢喜，说不准呵休烦恼。", "张千，且留人者。", "(张千云)理会的。", "(末见科，云)大人，小人是张鼎，替大人下乡劝农已回。", "听的大人升厅坐衙，有几宗合佥押文书，请相公佥押。"]'),
('yuanqu-7310','张孔目智勘魔合罗・金菊香','孟汉卿','元','元曲','yuanqu','','[]','这的是打家劫盗勘完的脏，这个是犯界茶盐取定的详该咱一地方。',50,'元曲/yuanqu.json','["这的是打家劫盗勘完的脏，这个是犯界茶盐取定的详该咱一地方。", "这个是新下到的符样，这个是官差纳送远仓粮。"]'),
('yuanqu-7311','张孔目智勘魔合罗・醋葫芦','孟汉卿','元','元曲','yuanqu','','[]','这的是沿河道便盖桥，这的是随州城新置仓。',79,'元曲/yuanqu.json','["这的是沿河道便盖桥，这的是随州城新置仓。", "这的是王首和那陈立赖人田庄，这的是张千殴打李万伤。", "(带云)怕官人不信呵，(唱)勾将来对词供状，这的是王阿张数次骂街坊。"]'),
('yuanqu-7312','张孔目智勘魔合罗・幺篇','孟汉卿','元','元曲','yuanqu','','[]','又不是公事忙，不由咱心绪穰。',543,'元曲/yuanqu.json','["又不是公事忙，不由咱心绪穰。", "若有那大公事失误了惹下灾殃，这些儿事务你早不记想，早难道贵人多忘。", "张千呵，且教他暂时停待莫慌张。", "(云)我只禀事，忘了。", "我再向大人行说去。", "(张千云)哥哥可怜见，与他说一声。", "(正末再见科)(府尹云)张鼎，你又来说甚么？(正末云)大人，恰才出的衙门，只见禀墙外有个受刑妇人，在那里声冤叫屈。", "知道的是他贪生怕死，不知道的则道俺衙门中错断了公事。", "相公试寻思波。", "(府尹云)这桩事是前官断定，萧令史该房。", "(正末云)萧令史，我须是六案都孔目，这是人命重事，怎生不教我知道？(令史云)你下乡劝农去了，难道你一年不回，我则管等着你？(正末云)将状子来我看。", "(令史云)你看状子。", "(正末看科，云)供状人刘玉娘，见年三十五岁，系河南府在城录事司当差民户。", "有夫李德昌，将带资本课银一十锭，贩南昌买卖。", "前去一年，并无音信。", "至七月内，有不知姓名男子一个来寄信，说夫李德昌在五道将军庙中染病，不能动止。", "五娘听言，慌速雇了头口，直至城南庙中，扶策到家，入门气绝，七窍迸流鲜血。", "玉娘即时报与小叔叔李文道，有小叔叔说玉娘与奸夫同谋，合毒药药杀丈夫。", "所供是实，并无虚捏。", "相公，这状子不中使。", "(令史云)买不的东西，可知不中使。", "(正末云)四下里无墙壁。", "(令史云)相公在露天坐衙哩。", "(正末云)上面都是窟笼。"]'),
('yuanqu-7313','张孔目智勘魔合罗・幺篇','孟汉卿','元','元曲','yuanqu','','[]','早是这为官的性忒刚，则你这为吏的见不长，则这一桩公事总荒唐。',76,'元曲/yuanqu.json','["早是这为官的性忒刚，则你这为吏的见不长，则这一桩公事总荒唐。", "那寄信人怎好不细防，更少这奸夫招状。", "(带云)相公，你想波。", "(唱)可怎生葫芦提推拥他亡云阳？。"]'),
('yuanqu-7314','张孔目智勘魔合罗・后庭花','孟汉卿','元','元曲','yuanqu','','[]','揽这场不分明的腌勾当，今日将子人来无事讲。',89,'元曲/yuanqu.json','["揽这场不分明的腌勾当，今日将子人来无事讲。", "你早则得福也萧司吏，则被你送了人也刘玉娘。", "我这里自斟量，则俺那官人要个明降。", "这杀人的要见伤，做贼的要见脏，犯奸的要见双，一行人怎问当？。"]'),
('yuanqu-7315','张孔目智勘魔合罗・双雁儿','孟汉卿','元','元曲','yuanqu','','[]','多则是没来山葫芦提打关防，待推辞早承向。',50,'元曲/yuanqu.json','["多则是没来山葫芦提打关防，待推辞早承向。", "眼见得三日时光如反掌，教我待不慌来怎个慌？待不忙来怎不忙？。"]'),
('yuanqu-7316','张孔目智勘魔合罗・浪里来煞','孟汉卿','元','元曲','yuanqu','','[]','那刘五娘罪责虚，萧令史口诤强。',57,'元曲/yuanqu.json','["那刘五娘罪责虚，萧令史口诤强。", "我把那衔冤负屈是非场，离家枉死李德昌，知他来怎生身丧？我直教平人无事罪人偿。", "(下)。"]'),
('yuanqu-7317','张孔目智勘魔合罗・中吕/粉蝶儿','孟汉卿','元','元曲','yuanqu','','[]','投至我勘问出强贼，早忧愁的寸肠粉碎，闷恹恹废寝忘食。',56,'元曲/yuanqu.json','["投至我勘问出强贼，早忧愁的寸肠粉碎，闷恹恹废寝忘食。", "你教我怎研穷，难决断，这其间详细，索用心机，要搜寻百谋千计。"]'),
('yuanqu-7318','张孔目智勘魔合罗・醉春风','孟汉卿','元','元曲','yuanqu','','[]','我好意儿劝他家，将一个恶头儿揣与自己。',64,'元曲/yuanqu.json','["我好意儿劝他家，将一个恶头儿揣与自己。", "原来口是祸之门，张鼎也你今日个，悔，悔！则要你那万法皆明，出脱的众人无事，全在你寸心不昧。"]'),
('yuanqu-7319','张孔目智勘魔合罗・叫声','孟汉卿','元','元曲','yuanqu','','[]','虎狼似恶公人，可扑鲁拥推、拥推阶前跪，我则见暗着气吞着声把头低。',174,'元曲/yuanqu.json','["虎狼似恶公人，可扑鲁拥推、拥推阶前跪，我则见暗着气吞着声把头低。", "(云)张千，且疏了他那枷者。", "(张千云)理会的。", "(做卸枷科，旦起身拜，云)谢了孔目，我改日送烧饼盒儿来。", "(做走科)(正末云)那里去？你去了呵，我替你男儿偿命那？(旦云)我则道饶了我来。", "(正末云)兀那妇人，你说你那词因来。", "若说的是呵，万事罢论；若说的不是呵。", "张千，准备下大棒子者。", "(唱)。"]'),
('yuanqu-7320','张孔目智勘魔合罗・喜春来','孟汉卿','元','元曲','yuanqu','','[]','你道是衔冤负屈吃尽亏，则你这致命图财本是谁？直打的皮开肉绽悔时迟。',47,'元曲/yuanqu.json','["你道是衔冤负屈吃尽亏，则你这致命图财本是谁？直打的皮开肉绽悔时迟。", "不是我强罗织，早说了是便宜。"]'),
('yuanqu-7321','张孔目智勘魔合罗・红绣鞋','孟汉卿','元','元曲','yuanqu','','[]','我领了严假限一朝两日，你恰才支吾到数次十回，又惹场六问共三推。',52,'元曲/yuanqu.json','["我领了严假限一朝两日，你恰才支吾到数次十回，又惹场六问共三推。", "听了你一篇话，全无有半星实，我跟前怎过得。"]'),
('yuanqu-7322','张孔目智勘魔合罗・迎仙客','孟汉卿','元','元曲','yuanqu','','[]','比及下拶指，先浸了麻槌，行仗的腕头加气力。',46,'元曲/yuanqu.json','["比及下拶指，先浸了麻槌，行仗的腕头加气力。", "直打得紫连青，青间赤。", "枉惹得棍棒临逼，待悔如何悔。"]'),
('yuanqu-7323','张孔目智勘魔合罗・白鹤子','孟汉卿','元','元曲','yuanqu','','[]','你道是便死呵则是屈，硬抵对不招实。',52,'元曲/yuanqu.json','["你道是便死呵则是屈，硬抵对不招实。", "(带云)我不问你别的，(唱)则问你出城时主何心？则他那入门死因何意？。"]'),
('yuanqu-7324','张孔目智勘魔合罗・幺篇','孟汉卿','元','元曲','yuanqu','','[]','莫不他同买卖是新伴当？(旦云)我不知道。',53,'元曲/yuanqu.json','["莫不他同买卖是新伴当？(旦云)我不知道。", "(正末唱)莫示是原茶酒旧相知？他可也怎生来寄家书？因甚上通消息？。"]'),
('yuanqu-7325','张孔目智勘魔合罗・幺篇','孟汉卿','元','元曲','yuanqu','','[]','那厮身材是长共短？肌肉儿瘦和肥？他可是面皮黑面皮黄？他可是有髭髟。',33,'元曲/yuanqu.json','["那厮身材是长共短？肌肉儿瘦和肥？他可是面皮黑面皮黄？他可是有髭髟。"]'),
('yuanqu-7326','张孔目智勘魔合罗・幺篇','孟汉卿','元','元曲','yuanqu','','[]','投至得推详出贼下落，搜寻的案完备。',48,'元曲/yuanqu.json','["投至得推详出贼下落，搜寻的案完备。", "兀的不熬煎的我鬓斑白，烦恼的我心肠碎？(云)兀那妇人，(唱)。"]'),
('yuanqu-7327','张孔目智勘魔合罗・幺篇','孟汉卿','元','元曲','yuanqu','','[]','莫不是身居在小巷东？家住在大街西？他可是甚坊曲甚庄村？何姓字何名讳？。',35,'元曲/yuanqu.json','["莫不是身居在小巷东？家住在大街西？他可是甚坊曲甚庄村？何姓字何名讳？。"]'),
('yuanqu-7328','张孔目智勘魔合罗・幺篇','孟汉卿','元','元曲','yuanqu','','[]','莫不是买油面为节食？莫不是裁段匹作秋衣？我问你为何事离宅院？有甚干来城内？(云)张千，明日是甚日？(张千云)明日是七月七。',305,'元曲/yuanqu.json','["莫不是买油面为节食？莫不是裁段匹作秋衣？我问你为何事离宅院？有甚干来城内？(云)张千，明日是甚日？(张千云)明日是七月七。", "(旦云)孔目哥哥，我想起来也。", "当年正是七月七，有一个卖魔合罗的寄信来，又与了我一个魔合罗儿。", "(正末云)兀那妇人，你那魔合罗有也无？如今在那里？(旦云)如今在俺家堂阁板儿上放着哩。", "(正末云)张千，与我取将来。", "(张千云)理会得。", "(做行科)我出的这门，来到这醋务巷。", "问人来，这是刘玉娘家里。", "我开开这门，家堂阁板上有个魔合罗，我拿着去。", "出的这门，来到衙门也。", "孔目哥哥，兀的不是个魔合罗儿。", "(正末云)是好一个魔合罗儿也。", "张千，装香来。", "魔合罗，是谁图财致命，李德昌怎生入门就死了？你对我说咱。", "(唱)。"]'),
('yuanqu-7329','张孔目智勘魔合罗・叫声','孟汉卿','元','元曲','yuanqu','','[]','你曾把愚痴的小孩提，教诲、教诲的心聪慧，若把这冤屈事说与勘官知。',32,'元曲/yuanqu.json','["你曾把愚痴的小孩提，教诲、教诲的心聪慧，若把这冤屈事说与勘官知。"]'),
('yuanqu-7330','张孔目智勘魔合罗・醉春风','孟汉卿','元','元曲','yuanqu','','[]','不强似你教幼女演裁缝，劝佳人学绣刺？要分别那不明白的重刑名，魔合罗全在你。',63,'元曲/yuanqu.json','["不强似你教幼女演裁缝，劝佳人学绣刺？要分别那不明白的重刑名，魔合罗全在你。", "你若出脱了这妇衔冤，我教人将你享祭，煞强如小儿博戏。"]'),
('yuanqu-7331','张孔目智勘魔合罗・滚绣球','孟汉卿','元','元曲','yuanqu','','[]','我与你曲湾湾画翠眉，宽绰绰穿绛衣，明晃晃凤冠霞帔，妆严的你这样何为？你若是到七月七，那其间乞巧的，将你做一家儿燕喜，你可便显神通，百事依随。',100,'元曲/yuanqu.json','["我与你曲湾湾画翠眉，宽绰绰穿绛衣，明晃晃凤冠霞帔，妆严的你这样何为？你若是到七月七，那其间乞巧的，将你做一家儿燕喜，你可便显神通，百事依随。", "比及你露十指玉笋穿针线，你怎不启一点朱唇说是非，教万代人知。"]'),
('yuanqu-7332','张孔目智勘魔合罗・倘秀才','孟汉卿','元','元曲','yuanqu','','[]','枉塑你似观音像仪，怎无那半点儿慈悲面皮？空着我盘问你将我不应对。',43,'元曲/yuanqu.json','["枉塑你似观音像仪，怎无那半点儿慈悲面皮？空着我盘问你将我不应对。", "我彻上下，细观窥到底。"]'),
('yuanqu-7333','张孔目智勘魔合罗・蛮姑儿','孟汉卿','元','元曲','yuanqu','','[]','我则道在那壁，原来在这里，谁想这底座儿下包藏着杀人贼。',43,'元曲/yuanqu.json','["我则道在那壁，原来在这里，谁想这底座儿下包藏着杀人贼。", "呼左右，上阶基，谁把高山认的？。"]'),
('yuanqu-7334','张孔目智勘魔合罗・鲍老儿','孟汉卿','元','元曲','yuanqu','','[]','须是你药杀他男儿，又带累他妻。',89,'元曲/yuanqu.json','["须是你药杀他男儿，又带累他妻。", "呀！你畅好会使拖刀计，漾一个瓦块儿在虚空里，怎生住的？呀！到了呵须按实田地，不要你狂言诈语，花唇巧舌，信口支持。", "则要你依头缕当，分星劈两，责状招实。"]'),
('yuanqu-7335','张孔目智勘魔合罗・鬼三台','孟汉卿','元','元曲','yuanqu','','[]','你和他从头里，传消息，沿路上曾撞着谁？(高山云)我不曾撞着人。',349,'元曲/yuanqu.json','["你和他从头里，传消息，沿路上曾撞着谁？(高山云)我不曾撞着人。", "(正末云)兀那老子，比及你见刘玉娘呵，城中先见谁来？(高山云)我想起来也。", "我入的城来，撒了一胞尿。", "(正末云)谁问你这个来？(高山云)我入城时，曾问人来，那人家门首吊着个龟盖。", "(正末云)敢是鳖壳？(高山云)直这等鳖杀我也。", "他那门前又有个石船。", "(正末云)敢是石碾子？(高山云)若是碾着，骨头都粉碎了。", "我见里面坐着个人，那厮是个兽医。", "(正末云)敢是个太医？(高山云)是个兽医。", "(正末云)怎生认的他是兽医？(高山云)既不是兽医，怎生做出这驴马的勾当？他叫做什么赛卢医？(正末云)刘玉娘，你认的赛卢医么？(旦云)他就是我小叔叔。", "(正末云)你叔嫂可和睦么？(旦云)俺不和睦(正末唱)听言罢，闷渐消，添欢喜，这官司才是实。", "呼左右问端的这医人与谁相识。"]'),
('yuanqu-7336','张孔目智勘魔合罗・剔银灯','孟汉卿','元','元曲','yuanqu','','[]','他又不是多年旧积，则是些冷物重伤了脾胃。',499,'元曲/yuanqu.json','["他又不是多年旧积，则是些冷物重伤了脾胃。", "则你那建中汤我想也堪医治，你则是加些附子当归。", "(李文道云)我随身带着药，拿与老夫人吃去。", "(张千云)将来，我送去。", "(做送药，回科)(正末与张千做耳喑科，云)张千，你看老夫人吃药如何？(张千云)理会的。", "(下，随上，云)孔目哥哥，老夫人吃了药，七窍迸流鲜血死了也。", "(正末云)赛卢医，你听得么？老夫人吃下药七窍迸流鲜血死了也。", "(李文道慌科，云)孔目哥哥救我咱。", "(正末云)我如今出脱你，你家里有甚么人？(李文道云)我有个老子。", "(正末云)多大年纪了？(李文道云)俺老子八十岁了。", "(正末云)老不加刑，则是罚赎。", "赛卢医，你若合的你老子，我便出脱的你。", "你若舍不的呵，出脱不的你。", "(李文道云)谢了哥哥。", "(正末云)我如今说与你：我便道赛卢医，你说小的。", "我便道谁合毒药来？你便道是俺老子来。", "我便道谁生情造意来？你便道是俺老子来。", "我便道谁拿银子来？你便道是俺老子来。", "我便道不是你么？你便道并不干小的事。", "你这般说，才出脱的你。", "(李文道云)谢了哥哥。", "(正末云)张千，你着他司房里去，你与我一步一棍打将那老子来者。", "(唱)那老子我亲身的，问他是实，(带云)张千，(唱)你只道见有人当官来告执。"]'),
('yuanqu-7337','张孔目智勘魔合罗・蔓青菜','孟汉卿','元','元曲','yuanqu','','[]','你说道是新刷卷的张司吏，一径的将你紧勾迫，教我火速来唤你。',47,'元曲/yuanqu.json','["你说道是新刷卷的张司吏，一径的将你紧勾迫，教我火速来唤你。", "但若有分毫不遵依，你将他拖向囚牢内。"]'),
('yuanqu-7338','张孔目智勘魔合罗・穷河西','孟汉卿','元','元曲','yuanqu','','[]','谁向宫中指攀着伊，是你那孝子曾参赛卢医。',46,'元曲/yuanqu.json','["谁向宫中指攀着伊，是你那孝子曾参赛卢医。", "又不是恰才新认义，须是你亲侄。", "哎！老丑生无端忒下的。"]'),
('yuanqu-7339','张孔目智勘魔合罗・柳青娘','孟汉卿','元','元曲','yuanqu','','[]','只着这些儿见识，瞒过这老无知。',70,'元曲/yuanqu.json','["只着这些儿见识，瞒过这老无知。", "却不你干悔万悔，泼水在地怎收拾。", "唬的个黄甘甘脸儿如地皮，可不道一言既出，便是驷马难追。", "已招伏，怎改易，要承抵。"]'),
('yuanqu-7340','张孔目智勘魔合罗・道和','孟汉卿','元','元曲','yuanqu','','[]','方知端的，知端的、虚事不能实。',115,'元曲/yuanqu.json','["方知端的，知端的、虚事不能实。", "忒跷蹊，教俺、教俺难根缉，教俺、教俺耽干系。", "使心机，啜赚出是和非。", "难支吾，难支对，难分说，难分细。", "那些、那些咱欢喜，咱伶俐，一行人个个服情罪。", "若非、若非有大理，这当堂假限刚三日，可不的势剑倒是咱先吃。"]'),
('yuanqu-7341','张孔目智勘魔合罗・煞尾','孟汉卿','元','元曲','yuanqu','','[]','想兄弟情亲如手足，怎下的生心将兄命亏。',41,'元曲/yuanqu.json','["想兄弟情亲如手足，怎下的生心将兄命亏。", "我将杀人贼斩首在云阳内，还报的这衔冤负屈鬼。"]'),
('yuanqu-7342','仙吕・赏花时北潇湘八景','沈和','元','元曲','yuanqu','','[]','休说功名皆是浪语，得失荣枯总是虚，便做道三公位待何如？如今得时务，尽荆棘是迷途。',40,'元曲/yuanqu.json','["休说功名皆是浪语，得失荣枯总是虚，便做道三公位待何如？如今得时务，尽荆棘是迷途。"]'),
('yuanqu-7343','幺篇・便是握雾拿云志已疏，咏月嘲风心愿足，我则待离尘世访江湖，寻','沈和','元','元曲','yuanqu','','[]','几个知音伴侣，我则待林泉下共樵夫。',17,'元曲/yuanqu.json','["几个知音伴侣，我则待林泉下共樵夫。"]'),
('yuanqu-7344','排哥南・远害全身，清风万古，堪羡范蠡归湖。不求玉带挂金鱼，甘分向','沈和','元','元曲','yuanqu','','[]','烟波做钓徒。',39,'元曲/yuanqu.json','["烟波做钓徒。", "绝尘世，远世俗，扁舟独驾水云居。", "嗟尘世，人斗取，蜗名蝇利待何如？。"]'),
('yuanqu-7345','鹊踏枝儿・见芳草映萍芜，听松风响寒芦，我则见落照渔村，水接天隅。','沈和','元','元曲','yuanqu','','[]','见一簇、帆归远浦，他每都是些不识字的慵懒渔夫。',23,'元曲/yuanqu.json','["见一簇、帆归远浦，他每都是些不识字的慵懒渔夫。"]'),
('yuanqu-7346','桂枝香南・扁舟湾住，在垂杨深处。<鼻勾>々似鼻息如雷，睡足了江南烟','沈和','元','元曲','yuanqu','','[]','听山寺晚钟，声声凄楚。',33,'元曲/yuanqu.json','["听山寺晚钟，声声凄楚。", "西沉玉兔，梦回初。", "本待要扶头去，清闲倒大福。"]'),
('yuanqu-7347','寄生草北・春景看山色晴岚翠，夏天听潇湘夜雨疏。九秋玩洞庭明月生南','沈和','元','元曲','yuanqu','','[]','浦，见平沙落雁迷芳渚。',45,'元曲/yuanqu.json','["浦，见平沙落雁迷芳渚。", "三冬赏江天暮雪飘飞絮，一任教乱纷纷柳絮舞空中，争如俺侬家鹦鹉洲边住。"]'),
('yuanqu-7348','乐安神南・闲来思虑，自从那日赋归欤，山河日月几盈虚，风光渐觉催寒','沈和','元','元曲','yuanqu','','[]','欲求生富贵，须下死工夫，且常教两眉舒。',19,'元曲/yuanqu.json','["欲求生富贵，须下死工夫，且常教两眉舒。"]'),
('yuanqu-7349','六幺序北・园塘外三丘地，篷窗下几卷书，他每傲人间驷马高车。每日家','沈和','元','元曲','yuanqu','','[]','相伴陶朱，吊问三闾。',71,'元曲/yuanqu.json','["相伴陶朱，吊问三闾。", "我将这《离骚》和这《楚辞》，来便收续，觉来时满眼青山暮，抖擞着绿蓑归去。", "看花开花落流年度，一任教春风桃李，更和这暮景桑榆。"]'),
('yuanqu-7351','二郎神醉射锁魔镜・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','皆是天将英雄，地神簇捧，施英猛。',33,'元曲/yuanqu.json','["皆是天将英雄，地神簇捧，施英猛。", "凭着我变化神通，都降了十大魔君洞。"]'),
('yuanqu-7352','二郎神醉射锁魔镜・油葫芦','无名氏','元','元曲','yuanqu','','[]','则这渺渺云山千万重，阻隔咱两弟兄，不期今日喜相逢。',102,'元曲/yuanqu.json','["则这渺渺云山千万重，阻隔咱两弟兄，不期今日喜相逢。", "咱两个十年来才把这樽席共，便休题一杯未尽笙歌送。", "咱说的这话正投，吃的这酒正浓。", "既然契厚为昆仲，咱今日休放酒杯空。", "(二郎云)吾神带酒也，贤弟请波。", "(末唱)。"]'),
('yuanqu-7353','二郎神醉射锁魔镜・醉扶归','无名氏','元','元曲','yuanqu','','[]','我这里忙把彪躯来耸，拽满宝雕弓。',131,'元曲/yuanqu.json','["我这里忙把彪躯来耸，拽满宝雕弓。", "远觑着兀良则是一望中，我这里款款放轻轻送。", "(做射箭科，云)着箭。", "(鬼力云)正中红心。", "(三箭中科)(末唱)不是我夸强卖弄，一箭箭把红心来中。", "(二郎云)兄弟也，不枉了武艺高强。", "将弓箭来，我也射三箭，争奈吾神带酒也。", "(拿弓科)(末唱)。"]'),
('yuanqu-7354','二郎神醉射锁魔镜・金盏儿','无名氏','元','元曲','yuanqu','','[]','我见他手拈着弓，箭离了桶，端详了弓箭无偏纵，弓开箭去渺无踪。',115,'元曲/yuanqu.json','["我见他手拈着弓，箭离了桶，端详了弓箭无偏纵，弓开箭去渺无踪。", "(二郎云)着箭。", "(鬼力云)正中红心。", "(两射科)(二郎云)西北下一点着箭。", "(外响亮一声科)(末唱)箭去呵，就地上火光三万丈，雷吼似五千声。", "则听的震天关如霹雳，彻上下半天红。"]'),
('yuanqu-7355','二郎神醉射锁魔镜・尾声','无名氏','元','元曲','yuanqu','','[]','这声响唬的三界鬼神惊，震的万里乾坤动，则听的山塌天摧地崩。',100,'元曲/yuanqu.json','["这声响唬的三界鬼神惊，震的万里乾坤动，则听的山塌天摧地崩。", "不似你心中无忖量，谁着你秋月般拽满雕弓。", "箭去半天红，不辨西东，惨雾阴云罩着碧空。", "这一箭恰便似摔碎玉笼，飞腾彩凤，早则么顿开金锁走蛟龙。", "(下)。"]'),
('yuanqu-7356','二郎神醉射锁魔镜・南吕/一枝花','无名氏','元','元曲','yuanqu','','[]','我亲奉着东华圣帝差，谨领着北极尊神令。',79,'元曲/yuanqu.json','["我亲奉着东华圣帝差，谨领着北极尊神令。", "驾祥云离帝阙，乘彩凤上天庭，怎敢消停？早来到北极西川郡。", "则为那玉帝行宣限的紧，二郎因当日酒饮了三巡，因此上惹起今朝祸根。"]'),
('yuanqu-7357','二郎神醉射锁魔镜・梁州','无名氏','元','元曲','yuanqu','','[]','则为那有胆量的那吒帅首，管待那无寻思的妙道真君。',161,'元曲/yuanqu.json','["则为那有胆量的那吒帅首，管待那无寻思的妙道真君。", "他平生武艺施逞尽。", "卖弄他神通广大，倚仗着筋力无伦。", "拽的弓开秋月，忽的箭去流星。", "谁想走了百眼金睛，那牛魔王死里逃生。", "他如今暗点下山鬼和那山精，俺如今准备下天兵和那地兵，则要你个二郎神千战千赢。", "符到，奉行。", "东华教玉帝敕如来命。", "怎敢道迟慢了半个时辰。", "今日个须当定罪名，怎敢道容情。"]'),
('yuanqu-7358','二郎神醉射锁魔镜・隔尾','无名氏','元','元曲','yuanqu','','[]','小神厅上开敕令，二郎去阶前仔细听，你不合射透驱邪院锁魔镜。',54,'元曲/yuanqu.json','["小神厅上开敕令，二郎去阶前仔细听，你不合射透驱邪院锁魔镜。", "则你的罪名、罪名又不轻，你去那玉阙天庭将是非来整。"]'),
('yuanqu-7359','二郎神醉射锁魔镜・牧羊关','无名氏','元','元曲','yuanqu','','[]','见如今如来怒，玉帝嗔，你罪过我待说一言难尽。',133,'元曲/yuanqu.json','["见如今如来怒，玉帝嗔，你罪过我待说一言难尽。", "为当日酒饮了三巡，今日里祸临着自身。", "你若是施谋略驱邪祟，显神力灭群精，恁时如来处饶了你那愆罚，恁时节玉皇行免你罪名。", "(二郎云)尊神，想吾神神通广大，变化多般，我则今日与那吒神，领本部下神兵，擒获此业畜，走一遭去。", "(末唱)。"]'),
('yuanqu-7360','二郎神醉射锁魔镜・骂玉郎','无名氏','元','元曲','yuanqu','','[]','我平生正直无私徇，你休怠慢莫消停，你索用心机打破他那迷魂阵。',52,'元曲/yuanqu.json','["我平生正直无私徇，你休怠慢莫消停，你索用心机打破他那迷魂阵。", "除免你那腹内愁，顿脱了眉上锁，释放了心头病。"]'),
('yuanqu-7361','二郎神醉射锁魔镜・感皇恩','无名氏','元','元曲','yuanqu','','[]','你须索舍死忘生，建立功勋。',72,'元曲/yuanqu.json','["你须索舍死忘生，建立功勋。", "则要你显神通，施谋略，逞精神。", "(云)若拿不住呵！你(唱)告与那那吒太子，他可敢扫荡魔君，他也敢擒妖怪，拿孽畜，领天兵。"]'),
('yuanqu-7362','二郎神醉射锁魔镜・采茶歌','无名氏','元','元曲','yuanqu','','[]','若是您个二郎神，显英灵，威伏天下鬼神惊。',93,'元曲/yuanqu.json','["若是您个二郎神，显英灵，威伏天下鬼神惊。", "灭尽妖晓那时分，恁时神鬼得安宁。", "(二郎云)则今日亲率天兵，擒拿金睛百眼鬼、九首牛魔王，走一遭去。", "天神且自放心，我随后便擒将两洞妖魔来也。", "(末唱)。"]'),
('yuanqu-7363','二郎神醉射锁魔镜・尾声','无名氏','元','元曲','yuanqu','','[]','则要你鞭敲金镫回军阵，统领天兵疾便行。',82,'元曲/yuanqu.json','["则要你鞭敲金镫回军阵，统领天兵疾便行。", "降妖魔，须用功。", "敢相持，敢战争，将妖魔，便诛尽。", "三尖刀劈那厮脑门，斩妖剑将那厮粉骨碎分身。", "若拿住妖魔呵，那时节证了本。", "(下)。"]'),
('yuanqu-7364','二郎神醉射锁魔镜・越调/斗鹌鹑','无名氏','元','元曲','yuanqu','','[]','冷飕飕杀气飘飘，气昂昂精神抖搜。',72,'元曲/yuanqu.json','["冷飕飕杀气飘飘，气昂昂精神抖搜。", "雄赳赳断怪除妖，威凛凛踏罡步斗。", "沉点点帅印悬腰，明晃晃双锋在手。", "马似熊，人似彪，左右列合后先锋，簇拥着元戎帅首。"]'),
('yuanqu-7365','二郎神醉射锁魔镜・紫花儿序','无名氏','元','元曲','yuanqu','','[]','凤翅盔簪缨款按，锁子甲战袄高提，狮蛮带纳榜轻兜。',109,'元曲/yuanqu.json','["凤翅盔簪缨款按，锁子甲战袄高提，狮蛮带纳榜轻兜。", "直赶遍三千世界，搜寻过四大神州。", "统领着戈矛，若撞见那两个妖魔吃剑头。", "半合儿也不勾，杀的那厮无处安身，有地难投。", "(二郎云)大小天兵，摆布的严整。", "(末云)摆开阵势者。", "(唱)。"]'),
('yuanqu-7366','二郎神醉射锁魔镜・金蕉叶','无名氏','元','元曲','yuanqu','','[]','四魔女休离了我左右，八角鬼枪刀在手。',40,'元曲/yuanqu.json','["四魔女休离了我左右，八角鬼枪刀在手。", "大刀鬼镇守着山岩洞口，狮陀鬼牢把定天关地轴。"]'),
('yuanqu-7367','二郎神醉射锁魔镜・调笑令','无名氏','元','元曲','yuanqu','','[]','他那里卖口，则管里絮无休。',65,'元曲/yuanqu.json','["他那里卖口，则管里絮无休。", "他道他世上寰中无对手，他道他阴符战策曾穷究，将兵书念得滑熟。", "咱两个横枪跃马且交半筹，敢则一阵里抹了芒头。"]'),
('yuanqu-7368','二郎神醉射锁魔镜・秃厮儿','无名氏','元','元曲','yuanqu','','[]','火轮起金蛇乱走，鞭梢动骤损骅骝。',41,'元曲/yuanqu.json','["火轮起金蛇乱走，鞭梢动骤损骅骝。", "我则见丝丝战尘遮了日头，早寻走路便搜求，无个缘由。"]'),
('yuanqu-7369','二郎神醉射锁魔镜・圣药王','无名氏','元','元曲','yuanqu','','[]','他将那军校收，弓箭丢，人慌马乱怎收救？你为帅首，怎的休！俺领着天兵神将紧追求，去来专拿住恁时休。',48,'元曲/yuanqu.json','["他将那军校收，弓箭丢，人慌马乱怎收救？你为帅首，怎的休！俺领着天兵神将紧追求，去来专拿住恁时休。"]'),
('yuanqu-7370','二郎神醉射锁魔镜・雪里梅','无名氏','元','元曲','yuanqu','','[]','你看我运机筹，咱两个遇着敌头。',37,'元曲/yuanqu.json','["你看我运机筹，咱两个遇着敌头。", "杀的他进退无门，死生也那难救，将身躯来倒缩。"]'),
('yuanqu-7371','二郎神醉射锁魔镜・幺篇','无名氏','元','元曲','yuanqu','','[]','显出我六臂三头，密匝匝列着戈矛，齐臻臻统领貔貅。',114,'元曲/yuanqu.json','["显出我六臂三头，密匝匝列着戈矛，齐臻臻统领貔貅。", "这厮命休，尽头，大小天兵齐下手。", "唬的他荒荒乱乱，心惊胆战，悲悲切切，鬼哭神愁。", "(二郎云)天神与我拿住者！(众神做拿住二妖科)(二郎云)将过这两个妖魔，执缚定，见上帝去来。", "(末唱)。"]'),
('yuanqu-7372','二郎神醉射锁魔镜・尾声','无名氏','元','元曲','yuanqu','','[]','今日将牛魔王百眼鬼都拿住也方才罢手，我得胜也引军回，直杀的妖魔望风儿走。',41,'元曲/yuanqu.json','["今日将牛魔王百眼鬼都拿住也方才罢手，我得胜也引军回，直杀的妖魔望风儿走。", "(同下)。"]'),
('yuanqu-7373','二郎神醉射锁魔镜・黄钟/醉花阴','无名氏','元','元曲','yuanqu','','[]','两下里交锋喊声起，差小圣到天兵阵里，看胜败，辨真实。',39,'元曲/yuanqu.json','["两下里交锋喊声起，差小圣到天兵阵里，看胜败，辨真实。", "若说着那吒，众神将应难比。"]'),
('yuanqu-7374','二郎神醉射锁魔镜・出队子','无名氏','元','元曲','yuanqu','','[]','齐臻臻天兵摆列，恶狠狠寻对叠，冬冬鼓响似春雷，火火火杂彩旗遮了太极，则见那二郎神当先战马嘶。',46,'元曲/yuanqu.json','["齐臻臻天兵摆列，恶狠狠寻对叠，冬冬鼓响似春雷，火火火杂彩旗遮了太极，则见那二郎神当先战马嘶。"]'),
('yuanqu-7375','二郎神醉射锁魔镜・刮地风','无名氏','元','元曲','yuanqu','','[]','则见那百眼鬼军前高叫起，咱两个比试高低。',82,'元曲/yuanqu.json','["则见那百眼鬼军前高叫起，咱两个比试高低。", "那吒神怒从心上起，可早变化了神威，显着那三头六臂，六般兵器，一来一往，一上一下，有似高飞。", "我见那吒神有气力，显出那变化容仪。"]'),
('yuanqu-7376','二郎神醉射锁魔镜・四门子','无名氏','元','元曲','yuanqu','','[]','牛魔王怎当神雄势，他见了也走如飞。',139,'元曲/yuanqu.json','["牛魔王怎当神雄势，他见了也走如飞。", "(院士云)俺这壁是那吒出马，三头六臂显神威，变化多般敢战敌。", "他是那玉结连环都帅首，杀的那雾罩乾坤天地迷。", "探子，慢慢的再说一遍。", "(末唱)那吒柿大叫如霹雳，显神通敢更疾。", "那业畜荒，怎敢道迟，引残兵望东走似飞。", "那吒神，好似狼转好是疾，直赶到黑风洞里。"]'),
('yuanqu-7377','二郎神醉射锁魔镜・古水仙子','无名氏','元','元曲','yuanqu','','[]','腾腾腾火焰起，见见见火轮上烟迷四下里，火火火降魔杵偏着，飕飕飕火星剑紧劈，他他他绣球儿高滚起，呀呀呀牛魔王怎生支持。',92,'元曲/yuanqu.json','["腾腾腾火焰起，见见见火轮上烟迷四下里，火火火降魔杵偏着，飕飕飕火星剑紧劈，他他他绣球儿高滚起，呀呀呀牛魔王怎生支持。", "来来来缚妖索紧绑住，是是是回军也齐将金镫系，俺俺俺得胜也尽和凯歌回。"]'),
('yuanqu-7378','二郎神醉射锁魔镜・尾声','无名氏','元','元曲','yuanqu','','[]','得胜也回军那些雄势，那泼妖魔怎生支持，将他那众妖魔尽拿回天阵里。',36,'元曲/yuanqu.json','["得胜也回军那些雄势，那泼妖魔怎生支持，将他那众妖魔尽拿回天阵里。", "(下)。"]'),
('yuanqu-7379','二郎神醉射锁魔镜・双调/新水令','无名氏','元','元曲','yuanqu','','[]','则为这逞雄威射贴显英豪，不思那二魔神顿开锁钥，疏狂惹罪愆，纵意犯天条。',53,'元曲/yuanqu.json','["则为这逞雄威射贴显英豪，不思那二魔神顿开锁钥，疏狂惹罪愆，纵意犯天条。", "今日个引动兵刀，俺可便驱邪鬼统军校。"]'),
('yuanqu-7380','二郎神醉射锁魔镜・香牌儿','无名氏','元','元曲','yuanqu','','[]','对神天将罪犯招，则为那二郎神性粗躁。',42,'元曲/yuanqu.json','["对神天将罪犯招，则为那二郎神性粗躁。", "他将那宝雕弓拽满怀中抱，王吉玎了的把青铜射破了。"]'),
('yuanqu-7381','二郎神醉射锁魔镜・雁儿落','无名氏','元','元曲','yuanqu','','[]','不想那二魔神将性命逃，奋恶气生残暴。',35,'元曲/yuanqu.json','["不想那二魔神将性命逃，奋恶气生残暴。", "奉天符玉帝敕，着俺这众神将都来到。"]'),
('yuanqu-7382','二郎神醉射锁魔镜・得胜令','无名氏','元','元曲','yuanqu','','[]','呀，四下里神将一周遭，二魔神犹自逞粗豪。',71,'元曲/yuanqu.json','["呀，四下里神将一周遭，二魔神犹自逞粗豪。", "则我这绣球千团火，二郎神轻轮动三尖两刃刀，骤战马相交，见杀气遮笼罩。", "俺轻舒展猿猱，将他那二魔神拿住了。"]'),
('yuanqu-7383','小尉迟将斗将认父归朝・仙吕/点绛唇','无名氏','元','元曲','yuanqu','','[]','你这般对垒交锋，到头都总，由柯梦。',34,'元曲/yuanqu.json','["你这般对垒交锋，到头都总，由柯梦。", "说甚军功，可兀的与你身儿上元无用。"]'),
('yuanqu-7384','小尉迟将斗将认父归朝・油葫芦','无名氏','元','元曲','yuanqu','','[]','好着我尽在嘻嘻冷笑中，我劝着他怎不从？(刘无敌云)我如今起兵在即，你怎说这等话？(正末唱)你将我这口中言看成做耳边风，你是一个朽木材怎比的他真梁栋？你是一个寒鸦',158,'元曲/yuanqu.json','["好着我尽在嘻嘻冷笑中，我劝着他怎不从？(刘无敌云)我如今起兵在即，你怎说这等话？(正末唱)你将我这口中言看成做耳边风，你是一个朽木材怎比的他真梁栋？你是一个寒鸦儿怎比的他丹山风？(刘无敌云)凭着父亲手下兵多将广，量大唐何足道哉。", "(正末唱)则咱这刘季真，怎比的他徐茂公？你本是那泼泥鳅打伙相随从，可便干闹起一座水晶宫。"]'),
('yuanqu-7385','小尉迟将斗将认父归朝・天下乐','无名氏','元','元曲','yuanqu','','[]','可不道将在谋而不在勇，哎，你一个将也波军，枉用功。',96,'元曲/yuanqu.json','["可不道将在谋而不在勇，哎，你一个将也波军，枉用功。", "(刘无敌云)凭着我坐下马，手中枪，有万夫不当之勇，料他到的那里。", "(正末唱)你道十八般武艺都晓通，卖弄你智量高，气势雄，你小可如刘黑闼王世充？。"]'),
('yuanqu-7386','小尉迟将斗将认父归朝・村里迓鼓','无名氏','元','元曲','yuanqu','','[]','那敬德鞭无虚举，举无不中。',194,'元曲/yuanqu.json','["那敬德鞭无虚举，举无不中。", "你便要一冲一撞，登时间早将你七擒七纵。", "倒不如且从容，莫赌斗，无惊恐。", "(刘无敌云)养爷，你说那里话。", "我到来日两阵之间，也不搦别人，单搦那尉迟敬德这老头儿出马。", "(正末唱)你待要两阵间，单搦那，鄂国公，(云)小将军，你和他厮杀呵，有个比喻。", "(刘无敌云)将何比喻？(正末唱)你恰便似病羊儿逢着大虫。", "(刘无敌云)养爷，你放心。", "我这一去，必然取胜。", "量他到的那里。", "(正末唱)。"]'),
('yuanqu-7387','小尉迟将斗将认父归朝・元和令','无名氏','元','元曲','yuanqu','','[]','你这一去少主吉多主凶，则宜止不宜动。',139,'元曲/yuanqu.json','["你这一去少主吉多主凶，则宜止不宜动。", "可不道箭安弦上慢张弓，方信道紧行无善踪。", "(刘无敌云)看各人的本事，你休阻我。", "(正末唱)你这般大惊小怪气冲冲，早难道军情事不透风。", "(刘无敌云)哎，养爷，俺这里七重围子，手摆布的银山铁壁相似，直着那敬德老儿觑也不敢觑。", "怎的敢和俺赌战？(正末唱)。"]'),
('yuanqu-7388','小尉迟将斗将认父归朝・游四门','无名氏','元','元曲','yuanqu','','[]','你便有那银山铁壁数十重，杀的你人似血胡同。',123,'元曲/yuanqu.json','["你便有那银山铁壁数十重，杀的你人似血胡同。", "则他那尉迟敬德敌头重，(刘无敌云)小番则今日下教场点军，好歹要与他交锋去来。", "(正末唱)你那里高叫响如钟，空逞恁的好喉咙。", "(刘无敌云)养爷你放心，看我活拿了敬德回来，取将相王侯，都在这一遭儿也。", "(正末唱)。"]'),
('yuanqu-7389','小尉迟将斗将认父归朝・胜葫芦','无名氏','元','元曲','yuanqu','','[]','哎，说甚么将相王侯元没种。',104,'元曲/yuanqu.json','["哎，说甚么将相王侯元没种。", "(云)小将军，只怕你敌不过敬德么？(刘无敌云)养爷，出军发马，也要个吉利。", "(正末唱)休烦恼你个小先锋，不争你九里山前厮闹哄。", "便要与刘沛公出力，我劝你韩元帅莫动，则被你羞杀我也蒯文通。"]'),
('yuanqu-7390','小尉迟将斗将认父归朝・后庭花','无名氏','元','元曲','yuanqu','','[]','你将一个后老子来忒紧攻，倒把一个亲爷来不敬重。',157,'元曲/yuanqu.json','["你将一个后老子来忒紧攻，倒把一个亲爷来不敬重。", "我道你是顶天立地的男儿汉，怎做了背祖离宗的牛马风？(刘无敌云)这说话一发说到那里去了。", "(正末唱)可不骂你个黑头虫，我则索教唆词讼。", "我这里絮叨叨言始终，你那里假惺惺做耳聋，甘落在人彀中。", "我猛然的觑面容，便思量俺那鄂国公。", "(刘无敌云)养爷，发起悲来，可是为何？(正末唱)。"]'),
('yuanqu-7391','小尉迟将斗将认父归朝・柳叶儿','无名氏','元','元曲','yuanqu','','[]','恰便似刀剜我这心痛，整整的二十年信息难通，大唐家不想你三军动。',608,'元曲/yuanqu.json','["恰便似刀剜我这心痛，整整的二十年信息难通，大唐家不想你三军动。", "我将你即发送，子父每得相逢。", "将军呵，你肯分的去出马争锋。", "(刘无敌云)恰才养爷说的那言语，好是奇怪，我就问他咱。", "养爷，我如今要与尉迟敬德交战，你这般阻当我呵，必有一个缘故，你对我实说，怕做甚么？(正末云)小将军，你着小校每回避着。", "(刘无敌云)一应人等，且各回避。", "唤着便来，不唤着您休来。", "(番卒云)理会的。", "(正末云)小将军，你是谁的儿？(刘无敌云)这个养爷老的混沌了，我是刘季真的儿。", "(正末云)你不是刘季真的儿。", "(刘无敌云)我不是他的儿，却是谁的儿？(正末云)小将军，你不知道，听我说与你。", "二十年前，你父亲降唐去了，撇下你留在我处，叫做尉迟保林，那时你才三岁。", "那刘季真他可无儿，收留你做了儿，就唤你做刘无敌。", "我数番家要和你说，我则怕刘季真知道，枉送了我的老命。", "你父亲临行时，留下一副披挂，在我处收着哩。", "是一条水磨鞭，一顶铁幞头，一副乌油甲、皂罗袍。", "你若见了尉迟敬德，则对的上这水磨鞭，便是你父亲。", "我就取的来，与你看波。", "(正末取衣甲上)(做看科)(刘无敌云)真个一副衣甲，一条好鞭。", "原来我就是鄂国公的儿。", "养爷不说呵，我怎生得知？(做悲科)(正末云)小将军。", "休烦恼，则怕刘季真知道。", "你是穿上这袍铠，披挂了我看。", "(刘无敌穿科，云)养爷，我比父亲如何？(正末云)好将军也，你这一去，怎生认你父亲？(刘无敌云)养爷，我这一去，单搦我父亲出马，与我交战呵，我自有个主意。"]'),
('yuanqu-7392','小尉迟将斗将认父归朝・赚煞尾','无名氏','元','元曲','yuanqu','','[]','则要你竭力报冤仇，在意的驱兵众。',142,'元曲/yuanqu.json','["则要你竭力报冤仇，在意的驱兵众。", "你尽孝何妨尽忠，这虎将门中无犬踪，端的是结束威风。", "我觑了他这英雄，身体仪容，不由我睹物思人泪点红。", "他带着这铁幞头把鸢肩来一耸，穿上这皂罗袍将虎腰来那动，(刘无敌云)养爷，我比父亲如何？(正末云)好将军也！(唱)分明是活脱下一个单鞭夺槊的尉迟恭。", "(下)。"]'),
('yuanqu-7393','小尉迟将斗将认父归朝・清江引','无名氏','元','元曲','yuanqu','','[]','房玄龄徐茂公真老傻，动不动将人骂。',46,'元曲/yuanqu.json','["房玄龄徐茂公真老傻，动不动将人骂。", "不知道我哄他，把我当实话，去买一瓶儿打刺酥吃着耍。", "(下)。"]'),
('yuanqu-7394','小尉迟将斗将认父归朝・中吕/粉蝶儿','无名氏','元','元曲','yuanqu','','[]','恼的我不邓邓忿气盈腮，可怎生另巍巍把咱单搦，不由我这胡髯乍满颔颏。',71,'元曲/yuanqu.json','["恼的我不邓邓忿气盈腮，可怎生另巍巍把咱单搦，不由我这胡髯乍满颔颏。", "人一似虎出山，马一似龙离海，凭着我枪疾鞭快，领雄兵穰穰垓垓，披挂上卓袍乌铠。"]'),
('yuanqu-7395','小尉迟将斗将认父归朝・醉春风','无名氏','元','元曲','yuanqu','','[]','我与你忙带上铁幞头，紧拴了红抹额。',273,'元曲/yuanqu.json','["我与你忙带上铁幞头，紧拴了红抹额。", "我若是交马处不拿了那个泼奴才，我可敢和姓也改改。", "凭着我千战千赢，百发百中，保护着一朝一代。", "(云)令人，报复去，道有尉迟恭下马也。", "(祗侯报科，云)喏，报的军师得知，有鄂国公来了也。", "(茂公云)道有请。", "(祗候云)请进去。", "(正末见科，云)军师唤老夫有何事商议？(茂公云)老将军来了也。", "奉圣人的命，今有北番刘季真下将战书来，单搦老将军出马。", "如今圣人着你领十万雄兵，与刘无敌交战。", "说他好生英勇难及哩。", "(正末云)军师，量那无名的小将，何足道哉！(房玄龄云)老将军，古语有云：凡人不可貌相，海水不可斗量。", "休轻觑了也。", "(正末唱)。"]'),
('yuanqu-7396','小尉迟将斗将认父归朝・迎仙客','无名氏','元','元曲','yuanqu','','[]','他曾上甚恶战场，他曾经甚大会垓，他则是劣马乍调嫌路窄。',120,'元曲/yuanqu.json','["他曾上甚恶战场，他曾经甚大会垓，他则是劣马乍调嫌路窄。", "向尉迟行说兵机，向尉迟行夸战策。", "我可甚冷笑哈哈，(茂公云)听的人说，那刘无敌也使一条水磨鞭，更胜过你老将军也。", "(正末云)军师，他也使鞭，我也使鞭，可也怪他不着。", "(唱)他正是担水向河头卖。"]'),
('yuanqu-7397','小尉迟将斗将认父归朝・红绣鞋','无名氏','元','元曲','yuanqu','','[]','兀的不龙欺于鱼鳖虾蟹，虎伏于狐兔狼豺，这小厮今年有些血光灾。',115,'元曲/yuanqu.json','["兀的不龙欺于鱼鳖虾蟹，虎伏于狐兔狼豺，这小厮今年有些血光灾。", "我鞭打碎他天灵盖，枪搠透他三思台，你更怕我敢慈悲生患害。", "(茂公云)论你年纪小时，休说一个刘无敌，便十个也不怕他，则可惜你年纪老了些。", "(正末云)军师，你说的差了也。", "(唱)。"]'),
('yuanqu-7398','小尉迟将斗将认父归朝・快活三','无名氏','元','元曲','yuanqu','','[]','虽然我六旬过血气衰，我犹敢把三五石家硬弓开。',46,'元曲/yuanqu.json','["虽然我六旬过血气衰，我犹敢把三五石家硬弓开。", "便小觑的我心长发短渐斑白，我可也怎肯伏年高迈？。"]'),
('yuanqu-7399','小尉迟将斗将认父归朝・鲍老儿','无名氏','元','元曲','yuanqu','','[]','我老则老杀场上有些气概，岂不闻虎瘦雄心在？(茂公云)则怕你近不的他么。',98,'元曲/yuanqu.json','["我老则老杀场上有些气概，岂不闻虎瘦雄心在？(茂公云)则怕你近不的他么。", "(正末唱)若是我不得胜之时怎的来，则怕羞见俺那唐十宰。", "料应他衣绝禄尽，时乖运拙，月值年灾，托赖着君王洪福，千秋万岁，神保天差。"]'),
('yuanqu-7400','小尉迟将斗将认父归朝・道合','无名氏','元','元曲','yuanqu','','[]','那泼奴才，泼奴才，就杀人场里闹垓垓，斗鞭来。',143,'元曲/yuanqu.json','["那泼奴才，泼奴才，就杀人场里闹垓垓，斗鞭来。", "教咱、教咱生嗔怪，教咱、教咱怎耽待。", "把钢鞭忙向手中抬，磕叉打的他连盔夹脑半斜歪。", "直遮腮，骨碌碌眼睁开，看承、看承似婴孩，抹着、抹着遭残害。", "略把、略把虎躯侧，扌昝住、扌昝住狮蛮带。", "那怕他铁打形骸，铜铸胚胎，早活挟过、活挟过这逆、逆、逆、逆贼来。"]'),
('yuanqu-7401','小尉迟将斗将认父归朝・随尾','无名氏','元','元曲','yuanqu','','[]','比破窦建德省些气力，擒王世充不利害。',57,'元曲/yuanqu.json','["比破窦建德省些气力，擒王世充不利害。", "遮莫是银山铁壁连环寨，凭着我英雄慷慨，兀良，我把那败残军自赶过李陵台。", "(下)。"]'),
('yuanqu-7402','小尉迟将斗将认父归朝・越调/斗鹌鹑','无名氏','元','元曲','yuanqu','','[]','俺兀自有美良川的威风，榆科园的猛气。',77,'元曲/yuanqu.json','["俺兀自有美良川的威风，榆科园的猛气。", "止不过病了秦琼，又不曾闲了敬德。", "都是我鞭打就的江山，枪刺成的社稷。", "这逆贼，敢料敌，则问他武艺如何，就待欺负我年华老矣。"]'),
('yuanqu-7403','小尉迟将斗将认父归朝・紫花儿序','无名氏','元','元曲','yuanqu','','[]','我施逞会挟人捉将，显耀会撞阵冲营，卖弄会挝鼓夺旗。',89,'元曲/yuanqu.json','["我施逞会挟人捉将，显耀会撞阵冲营，卖弄会挝鼓夺旗。", "他须披不的两重铠甲，带不的三顶头盔，敢和我相持？便做有铜铸就的天灵和那铁背脊，鞭着处粉零麻碎。", "今日个将遇敌头，直杀的他马不停蹄。"]'),
('yuanqu-7404','小尉迟将斗将认父归朝・小桃红','无名氏','元','元曲','yuanqu','','[]','觑了这北番军校好着我笑微微，我比他争些年纪。',141,'元曲/yuanqu.json','["觑了这北番军校好着我笑微微，我比他争些年纪。", "(刘无敌云)看了我血气方刚，后生可畏。", "量你老人家到的那里。", "(正末唱)你倚仗着血气方刚有雄势，你可也便休题，则我这不剌剌趁日追风骑。", "乌油甲密砌，点刚枪锋利，岂不闻老将会兵机？(刘无敌云)兀那老将军，你别着一个出马来，你去自在罢。", "(正末唱)。"]'),
('yuanqu-7405','小尉迟将斗将认父归朝・鬼三台','无名氏','元','元曲','yuanqu','','[]','雁翅张，鱼鳞砌，列寨栅，攒军队。',79,'元曲/yuanqu.json','["雁翅张，鱼鳞砌，列寨栅，攒军队。", "齐臻臻排开阵势，则听的悠悠的画角吹，冬冬的花腔鼓击。", "小可的见了肝胆碎。", "便英雄怕不魂魄飞。", "都是些沉点点鞭简挝锤。", "明晃晃枪刀剑戟。"]'),
('yuanqu-7406','小尉迟将斗将认父归朝・调笑令','无名氏','元','元曲','yuanqu','','[]','往日间，但逢敌，骤马横枪觉甚的。',54,'元曲/yuanqu.json','["往日间，但逢敌，骤马横枪觉甚的。", "我攒搠丢打不曾离，不曾离前心两肋。", "我见他遮截得来省气力，倒拖斗的我气喘狼藉。"]'),
('yuanqu-7407','小尉迟将斗将认父归朝・麻郎儿','无名氏','元','元曲','yuanqu','','[]','谁使的你来认义？(刘无敌云)是宇文养爷说来。',94,'元曲/yuanqu.json','["谁使的你来认义？(刘无敌云)是宇文养爷说来。", "(正末唱)谁使的你敢相持？(刘无敌云)是刘季真来。", "父亲不信呵，兀的水磨鞭信物在此。", "(正末云)将来我看。", "(唱)我把信物接将来手里，看有甚亲题标记。"]'),
('yuanqu-7408','小尉迟将斗将认父归朝・幺篇','无名氏','元','元曲','yuanqu','','[]','兀的，我临老也，尉迟，喜欢来那似今日。',68,'元曲/yuanqu.json','["兀的，我临老也，尉迟，喜欢来那似今日。", "自相别存亡不知，怎想你成人长立？(刘无敌做悲认科，云)父亲一自相别，可早二十年光景也。", "(正末唱)。"]'),
('yuanqu-7409','小尉迟将斗将认父归朝・络丝娘','无名氏','元','元曲','yuanqu','','[]','这几年不通个信息，怎想着今朝得见你。',92,'元曲/yuanqu.json','["这几年不通个信息，怎想着今朝得见你。", "恰才厮杀处你是赢不的，可是让我哩？(刘无敌云)我特的认父亲来，恰才两阵之前，被众将压着，难以明认，我故意佯输诈败。", "(正末唱)好儿也，方信道后生可畏。"]'),
('yuanqu-7410','小尉迟将斗将认父归朝・收尾','无名氏','元','元曲','yuanqu','','[]','团圆了尉迟公，烦恼杀刘家里，只明日早来到营中宴喜。',52,'元曲/yuanqu.json','["团圆了尉迟公，烦恼杀刘家里，只明日早来到营中宴喜。", "这的是天指引一个小将军，共扶持我那当今大唐国。", "(下)。"]'),
('yuanqu-7411','小尉迟将斗将认父归朝・双调/新水令','无名氏','元','元曲','yuanqu','','[]','则俺那大唐家新添了一个玉麒麟，疑怪他两三番搦咱出阵。',90,'元曲/yuanqu.json','["则俺那大唐家新添了一个玉麒麟，疑怪他两三番搦咱出阵。", "斗起我美良川狠气势，榆科园恶精神。", "我将这水磨鞭款款摩抡，只待打碎他脑盖纷纷，谁承望共我关亲。", "若不是所说原因，险些儿生扭做单雄信。"]'),
('yuanqu-7412','小尉迟将斗将认父归朝・驻马听','无名氏','元','元曲','yuanqu','','[]','当日离分，痛煞煞生抛掌上珍：今朝厮认，笑吟吟还猜做梦中人。',65,'元曲/yuanqu.json','["当日离分，痛煞煞生抛掌上珍：今朝厮认，笑吟吟还猜做梦中人。", "二十年访不出死和存，几千回摆不下愁将恨。", "心暗忖，甚福也，得见这团圆分！。"]'),
('yuanqu-7413','小尉迟将斗将认父归朝・沽美酒','无名氏','元','元曲','yuanqu','','[]','我兴心的报主恩，竭力的扫胡尘。',44,'元曲/yuanqu.json','["我兴心的报主恩，竭力的扫胡尘。", "常言道上阵无过子父军，只待一鞭儿把番兵杀尽，扶宇宙定乾坤。"]'),
('yuanqu-7414','小尉迟将斗将认父归朝・太平令','无名氏','元','元曲','yuanqu','','[]','他可便约定把唐朝归顺，(茂公云)他既降唐，怎生不同你来？(正末唱)索甚么拔树寻根，将逆贼不留龆龄，做功劳好将身进。',84,'元曲/yuanqu.json','["他可便约定把唐朝归顺，(茂公云)他既降唐，怎生不同你来？(正末唱)索甚么拔树寻根，将逆贼不留龆龄，做功劳好将身进。", "他呵既然的便肯，就准认了俺父亲，呀，又怎敢言而无信？。"]'),
('yuanqu-7415','小尉迟将斗将认父归朝・雁儿落','无名氏','元','元曲','yuanqu','','[]','笑你个莽军师可也忒认真，把我个老尉迟空生忿。',42,'元曲/yuanqu.json','["笑你个莽军师可也忒认真，把我个老尉迟空生忿。", "再不审比干心有是非，直着的张仪口难争论。"]'),
('yuanqu-7416','小尉迟将斗将认父归朝・得胜令','无名氏','元','元曲','yuanqu','','[]','呀，则为这二十三的小将军，险送了七十老功臣。',410,'元曲/yuanqu.json','["呀，则为这二十三的小将军，险送了七十老功臣。", "(云)孩儿，你拜了军师者。", "(唱)你将这徐茂公亲身拜，(小尉迟做拜科，云)军师受小将一礼。", "(茂公云)小将军免礼。", "刘季真安在？(正末云)孩儿，你拿过刘季真来者。", "(卒子做拿刘季真跪见科)(正末唱)分付与你两事家刘季真。", "欢欣，同扶着唐天子方兴运，殷也波勒，多谢你个房玄龄落保人。", "(茂公云)这是刘季真么？(小尉迟云)则这厮便是刘季真。", "(茂公云)令人，将刘季真推出辕门，斩讫报来。", "(刘季真云)罢、罢、罢，他本是尉迟公的孩儿，没来由养的他长大成人，倒将我来做降唐的礼物。", "你家父子都一样这等没仁没义的，我死去与我家老子说，少不的来报你。", "(卒子拿刘季真下)(茂公云)尉迟公，你父子每望阙跪着，听圣人的命。", "(词云)则为你勇敢无前，俺唐主宠任多年。", "生撇下孩儿不题，再相逢这是天缘。", "鄂国公赐金千两，加食邑万顷庄田。", "小尉迟金吾上将，作先锋世掌军权。", "将斗将同扶王室，鞭对鞭父子团圆。", "(正末小尉迟谢恩科)。"]'),
('yuanqu-7417','保成公径赴渑池会・正宫/端正好','高文秀','元','元曲','yuanqu','','[]','何须你列枪刀，排队伍，成和败全在相如。',299,'元曲/yuanqu.json','["何须你列枪刀，排队伍，成和败全在相如。", "(廉颇云)大夫，你此一去，敢有去的路儿，无那回来的路儿。", "(正末唱)元帅怕有去路道我无回路，他将我厮小觑忒欺负，则今日离赵国践程途。", "他若是怀奸诈，我可便使机谋，(赵成公云)大夫，则要你疾去早来，小心在意者。", "(正末云)主公放心也。", "(唱)我手里怎肯道甘献与他这荆山玉。", "(下)(廉颇云)主公，相如去了也。", "他这一去，舍命丧身之路。", "玉璧不能回国，相国必然久困于秦，教邻邦耻笑也。", "(赵成公云)将军，相如如此一去，胜负未知。", "他若是不得秦城，完璧回国，那其间我将他重重加官赐赏，未为晚矣。", "则为这昭公使计用心机，故教两国起相持。", "你若是完璧偿城得两便，那其间封官赐赏把名题。", "(下)。"]'),
('yuanqu-7418','保成公径赴渑池会・仙吕/点绛唇','高文秀','元','元曲','yuanqu','','[]','则恐怕士马相残，庶民涂炭，怎敢道违程限。',38,'元曲/yuanqu.json','["则恐怕士马相残，庶民涂炭，怎敢道违程限。", "人生于天地之间，播一个清史内名扬赞。"]'),
('yuanqu-7419','保成公径赴渑池会・混江龙','高文秀','元','元曲','yuanqu','','[]','这一场也不用军卒百万，(亲随云)大夫，咱只是单人独马到秦国，凭着甚么武艺得玉宝回国也？(正末唱)凭着我唇枪舌剑定江山。',225,'元曲/yuanqu.json','["这一场也不用军卒百万，(亲随云)大夫，咱只是单人独马到秦国，凭着甚么武艺得玉宝回国也？(正末唱)凭着我唇枪舌剑定江山。", "见如今河清海晏，黎庶宽安。", "出口夸言离赵国，铺谋定计入潼关。", "因此上乘骏马，跨雕鞍，披星月，冒风寒，完玉璧，要回还。", "解了那麒麟殿上赵公忧，更和这虎狼丛里英雄汉。", "也不望封官赐赏，则愿的人马平安。", "(亲随云)大夫，想无瑕玉璧，是俺赵国之宝，秦国又不知道，因何将此无瑕之宝，自送于秦国？咱正是自招其祸也。", "(正末云)你不知道，听我说与你。", "(唱)。"]'),
('yuanqu-7420','保成公径赴渑池会・油葫芦','高文秀','元','元曲','yuanqu','','[]','想当日文武群臣列两班，玉阶前，仰圣颜，则听得秦邦使命到邯郸。',127,'元曲/yuanqu.json','["想当日文武群臣列两班，玉阶前，仰圣颜，则听得秦邦使命到邯郸。", "要无瑕玉璧相观看，他可便许连城换易成虚诞。", "(亲随云)大夫，既然秦国将十五座连城换此玉璧，便送来也不亏俺赵国。", "(正末唱)他要玉璧容易取，与连城呵恐作难。", "他将俺邻邦欺压相轻慢，俺若是起征战在霎时间。"]'),
('yuanqu-7421','保成公径赴渑池会・天下乐','高文秀','元','元曲','yuanqu','','[]','则为这两国干戈若动烦，数十载难也波安，那其间悔后晚，则这个蔺相如正直非占奸。',431,'元曲/yuanqu.json','["则为这两国干戈若动烦，数十载难也波安，那其间悔后晚，则这个蔺相如正直非占奸。", "我言词有定准，无转关，我可便定兴亡在这番。", "(亲随云)大夫，旬日之间，到于秦邦也。", "(正末云)早来至府门首也。", "报复去，道有赵国中大夫蔺相如在于门前。", "(卒子云)理会的。", "中大夫，大王着你过去。", "(亲随云)大夫过去，亲随在于何处？(正末云)你则在门首，我自过去。", "(正末做见科)(秦昭公云)赵国使命，官居何职，为何至于秦邦？(正末云)小官赵国中大夫蔺相如，奉赵国命，差小官奉玉璧入秦。", "(秦昭公云)既然成公差你送玉璧入秦，今玉璧在于那里？(正末云)玉璧见在此，请公子观看。", "(秦昭公云)将玉璧来，我试看咱。", "(做看科，云)是好玉璧也。", "这玉璧当初您赵国怎生得来？(正末云)公子，这玉璧当初本不在赵国生，乃楚国荆山出此玉。", "有一人乃是卞和，得此玉进于楚公，楚公不识。", "次后卞和三进，楚公才知是玉，后来落在俺赵国。", "(秦昭公云)原来此玉不为真福，也则如此出产。", "这玉再有甚么奇妙？卞和因何知道他是无瑕玉璧也？(正末唱)。"]'),
('yuanqu-7422','保成公径赴渑池会・金盏儿','高文秀','元','元曲','yuanqu','','[]','这玉出荆山，长荆山，卞和为此可便遭危难。',79,'元曲/yuanqu.json','["这玉出荆山，长荆山，卞和为此可便遭危难。", "自离了楚国到邯郸，看承的如气命，爱惜似心肝。", "(秦昭公云)量此玉非为大宝，不为罕哉！(正末唱)您若将容易得，便做等闲看。"]'),
('yuanqu-7423','保成公径赴渑池会・醉扶归','高文秀','元','元曲','yuanqu','','[]','饥不可为粮饭，冻不可御风寒。',97,'元曲/yuanqu.json','["饥不可为粮饭，冻不可御风寒。", "(秦昭公云)你说这玉不是大宝，可怎生上下无瑕，一色光润，内外莹然？真乃世之宝也。", "(正末唱)便做道温润光辉有甚罕见，如今惹祸招灾患。", "无纹藻那能入眼？他端的费雕琢难磨渲。"]'),
('yuanqu-7424','保成公径赴渑池会・河西后庭花','高文秀','元','元曲','yuanqu','','[]','一个汤伊尹除佞奸，一个姜太公伐暴残。',101,'元曲/yuanqu.json','["一个汤伊尹除佞奸，一个姜太公伐暴残。", "有一个孝子周公旦，一个忠臣殷比干。", "(秦昭公云)我道你说甚么大宝，你可将上古名人比并，你在我跟前攀今揽古。", "(正末唱)非是我古今攀，他都是后人楷范，你看的这无瑕玉似等闲。"]'),
('yuanqu-7425','保成公径赴渑池会・尾声','高文秀','元','元曲','yuanqu','','[]','且归到驿亭中，疾便把程途盼。',95,'元曲/yuanqu.json','["且归到驿亭中，疾便把程途盼。", "便荡过黄河退滩，一路上殷勤休怠慢。", "早回还，教公子开颜；语言间，别有机关。", "我若是有差错有输亏誓不还，他必然令人追赶。", "我若出的潼关一难，你看我不分星夜到邯郸。", "(下)。"]'),
('yuanqu-7426','保成公径赴渑池会・中吕/粉蝶儿','高文秀','元','元曲','yuanqu','','[]','不避那千里驱驰，尽忠心与国家出力。',58,'元曲/yuanqu.json','["不避那千里驱驰，尽忠心与国家出力。", "都则为秦昭王将诸国吞食，他许连城换玉璧，心怀奸计。", "若不是片语投机，论阿谀揣情磨意。"]'),
('yuanqu-7427','保成公径赴渑池会・醉春风','高文秀','元','元曲','yuanqu','','[]','我夜月离秦邦，飞星投赵国，无瑕玉宝得全归，到大是喜、喜。',49,'元曲/yuanqu.json','["我夜月离秦邦，飞星投赵国，无瑕玉宝得全归，到大是喜、喜。", "他则待恣意贪饕，纵心残暴，我则待暗施谋智。"]'),
('yuanqu-7428','保成公径赴渑池会・迎仙客','高文秀','元','元曲','yuanqu','','[]','臣不曾调鼎鼐，又不曾理盐梅，怎做的那济为楫旱为霖伊傅比。',96,'元曲/yuanqu.json','["臣不曾调鼎鼐，又不曾理盐梅，怎做的那济为楫旱为霖伊傅比。", "(赵成公云)想昭公乃虎狼之国，兴心贪图玉璧，你完宝而还，实为难矣。", "(正末唱)我则待罢刀兵，安社稷。", "则要的物阜民熙，则俺这为臣子要当竭力。"]'),
('yuanqu-7429','保成公径赴渑池会・红绣鞋','高文秀','元','元曲','yuanqu','','[]','怎消的加官进位？怎消的荫子封妻？上卿之职位何极。',47,'元曲/yuanqu.json','["怎消的加官进位？怎消的荫子封妻？上卿之职位何极。", "高牙乘驷马，大纛列红衣，我这里便谢深恩感至德。"]'),
('yuanqu-7430','保成公径赴渑池会・普天乐','高文秀','元','元曲','yuanqu','','[]','不肯将善人推，则待把贤门闭。',239,'元曲/yuanqu.json','["不肯将善人推，则待把贤门闭。", "将忠良妒忌，于礼何为？(廉颇云)相如，你此一去送玉璧，非为赵国，因你邀买功名，滥叨爵禄。", "(正末唱)不说那定国谋，安邦计，倒与我个滥叨功名弥天罪，见如今赏罚权在公子操持，公子掌朝廷明似皎日。", "将军倾社稷危如累卵，蔺相如辅皇图稳若磐石。", "(赵成公云)廉将军，今日昭公既来邀请，渑池会上，去好？不去何如？(廉颇云)主公，想昭公心生奸诈，故设此会，智赚主公，不可赴会。", "不如起大势雄兵，与他对敌。", "(正末云)主公不可起兵。", "(赵成公云)大夫，怎生不可起兵？(正末唱)。"]'),
('yuanqu-7431','保成公径赴渑池会・上小楼','高文秀','元','元曲','yuanqu','','[]','早难道"颠而不扶，危而不持"。',88,'元曲/yuanqu.json','["早难道\"颠而不扶，危而不持\"。", "你若是谋动干戈，境内分崩，四方离析。", "(廉颇云)相如，你说不要起兵，依着你怎生是好？(正末唱)则不如叙彝伦，正纲常，躬行仁义，我则要效唐虞太平之治。"]'),
('yuanqu-7432','保成公径赴渑池会・幺篇','高文秀','元','元曲','yuanqu','','[]','商贾每阻了行旅，庄农每费了耕织。',115,'元曲/yuanqu.json','["商贾每阻了行旅，庄农每费了耕织。", "将他这仓廪耗散，府库空虚，士卒疲弊。", "(赵成公云)依着你呵，怎生？(正末唱)凭着我不伤财，不害民，一人一骑，(廉颇云)则依着我，起军与他交战。", "自古道：\"养军千日，用在一朝。", "\"(正末唱)便休题养军千日。"]'),
('yuanqu-7433','保成公径赴渑池会・十二月','高文秀','元','元曲','yuanqu','','[]','盟府是公卿宰职，对着这文武班齐。',49,'元曲/yuanqu.json','["盟府是公卿宰职，对着这文武班齐。", "你道是有危有难，我道来无是无非。", "打赌赛输了呵休悔，则要你言语诚实。"]'),
('yuanqu-7434','保成公径赴渑池会・尧民歌','高文秀','元','元曲','yuanqu','','[]','呀，你说道面搽红粉的不便宜，则我这六阳会首不相亏。',140,'元曲/yuanqu.json','["呀，你说道面搽红粉的不便宜，则我这六阳会首不相亏。", "人言为信永无称，昧己瞒心把天欺。", "知也波知，与皇家作柱石，不比儿曹辈。", "(赵成公云)则今日点就百十骑人马，都要轻弓短箭，善马熟人，便索赴渑池会，走一遭去。", "(廉颇云)主公先行，某随后领大势雄兵，接应主公去。", "(正末云)主公放心也。", "(唱)。"]'),
('yuanqu-7435','保成公径赴渑池会・尾声','高文秀','元','元曲','yuanqu','','[]','不须军马多，则消的数骑随。',46,'元曲/yuanqu.json','["不须军马多，则消的数骑随。", "看了那三川八水西秦地，向渑池赴会。", "我则怕盼程途心急马行迟。", "(下)。"]'),
('yuanqu-7436','保成公径赴渑池会・正宫/端正好','高文秀','元','元曲','yuanqu','','[]','为家邦，遭途旅，岂辞劳千里驰驱？三川八水的这秦邦路，将渑池会亲身赴。',34,'元曲/yuanqu.json','["为家邦，遭途旅，岂辞劳千里驰驱？三川八水的这秦邦路，将渑池会亲身赴。"]'),
('yuanqu-7437','保成公径赴渑池会・倘秀才','高文秀','元','元曲','yuanqu','','[]','我则见他叙寒温相别间阻，让座位尊宾敬主，笑吟吟高捧定金樽碧玉壶，排珍馔，饮芳醑，何曾道断续？。',47,'元曲/yuanqu.json','["我则见他叙寒温相别间阻，让座位尊宾敬主，笑吟吟高捧定金樽碧玉壶，排珍馔，饮芳醑，何曾道断续？。"]'),
('yuanqu-7438','保成公径赴渑池会・滚绣球','高文秀','元','元曲','yuanqu','','[]','您待要讲圣贤，论今古，称尧舜禹汤文武，他都是圣明君统绪鸿图。',92,'元曲/yuanqu.json','["您待要讲圣贤，论今古，称尧舜禹汤文武，他都是圣明君统绪鸿图。", "他将那仁义举，凶暴除，不比您恃刚强并吞攻取，普天下讴歌道泰咸伏。", "桀纣因饰非拒谏亡家国，尧舜为发政施仁立帝都，强教的四海无虞。"]'),
('yuanqu-7439','保成公径赴渑池会・倘秀才','高文秀','元','元曲','yuanqu','','[]','问道是七国臣能文能武，一人下为肱为股，辅助的社稷安宁万姓伏。',52,'元曲/yuanqu.json','["问道是七国臣能文能武，一人下为肱为股，辅助的社稷安宁万姓伏。", "文通《三坟》典，武解《六韬》书，听小臣细数。"]'),
('yuanqu-7440','保成公径赴渑池会・滚绣球','高文秀','元','元曲','yuanqu','','[]','齐孙膑减灶法有智谋，(秦昭公云)赵国有甚人物？(正末唱)赵李牧示怯弱扫夷虏，(秦昭公云)燕国有甚么英杰？(正末唱)燕乐毅破齐不攻不取，(秦昭公云)齐国有甚英雄？',320,'元曲/yuanqu.json','["齐孙膑减灶法有智谋，(秦昭公云)赵国有甚人物？(正末唱)赵李牧示怯弱扫夷虏，(秦昭公云)燕国有甚么英杰？(正末唱)燕乐毅破齐不攻不取，(秦昭公云)齐国有甚英雄？(正末唱)田穰苴诛庄贾文武全俱，(秦昭公云)魏国有甚么英雄？(正末唱)魏吴起犒士卒亲吮疽，(秦昭公云)俺秦国有甚么人物？(正末唱)武安君出奇兵快捣虚，(秦昭公云)齐国再有甚么好汉？(正末唱)齐田单火牛阵有如脱兔，(秦昭公云)您赵国有甚英雄？(正末唱)则俺那廉将军有勇气善野战长驱。", "(秦昭公云)七国多有说谎之客也。", "(正末唱)苏秦、张仪和陈轸，(秦昭公云)还有几个说客？(正末唱)蔡泽、荀卿共范雎，(秦昭公云)此等之人，七国之中，显耀英名，乃人中之杰也。", "(正末唱)他都是权谋术数之徒。"]'),
('yuanqu-7441','保成公径赴渑池会・塞鸿秋','高文秀','元','元曲','yuanqu','','[]','将主公向筵前鼓瑟相欺负，(秦昭公云)大夫，我击缶则便了也。',213,'元曲/yuanqu.json','["将主公向筵前鼓瑟相欺负，(秦昭公云)大夫，我击缶则便了也。", "(正末唱)请秦公击缶我也相凌辱。", "(秦昭公云)成公可将十五城与我为寿，免两国之刀兵。", "(正末唱)要俺十五城为寿将秦助，(云)小臣问大王要些回奉之物也。", "(秦昭公去)要什么回物？(正末唱)要你那咸阳城回赐休推故。", "(秦昭公云)想赵国相如无礼，你怎敢将言悔慢我？刀斧手，与我靠前来。", "(正末云)大王，俺为臣者生死不避也。", "(唱)五步内之间，霎时间颈血飞红雨，大家去史书中万代标名目！。"]'),
('yuanqu-7442','保成公径赴渑池会・伴读书','高文秀','元','元曲','yuanqu','','[]','我见他掣龙泉席上舞，整虎躯轻移步。',90,'元曲/yuanqu.json','["我见他掣龙泉席上舞，整虎躯轻移步。", "俺主公战战兢兢身无措，他正是撩蜂剔蝎胡为做。", "又无甚兜鍪铠甲相遮护，使不着胆大心粗。", "(赵成公云)二人在筵前舞剑，有伤我之意，似此怎了也？(正末唱)。"]'),
('yuanqu-7443','保成公径赴渑池会・尾声','高文秀','元','元曲','yuanqu','','[]','我见他金爪武士排着行伍，俺那里铁甲将军领着士卒。',113,'元曲/yuanqu.json','["我见他金爪武士排着行伍，俺那里铁甲将军领着士卒。", "你无故言盟定计谋，有失尊卑礼法疏。", "鼓瑟筵前厮羞辱，强要城池心狠毒。", "送俺上雕轮驷马车，敢有二个兴心进一步，拚了个陨首捐躯。", "我和他爱的做，和你那锦片也似秦川做不的主！(同成公等下)。"]'),
('yuanqu-7444','保成公径赴渑池会・双调/新水令','高文秀','元','元曲','yuanqu','','[]','托赖着当今帝王胜唐尧，则俺这文共武尽心忠孝。',61,'元曲/yuanqu.json','["托赖着当今帝王胜唐尧，则俺这文共武尽心忠孝。", "又不为居庙廊愁戚戚，治家国鬓萧萧。", "廉颇哎，则为你跋扈矜骄，气的我染疾病进汤药。"]'),
('yuanqu-7445','保成公径赴渑池会・步步娇','高文秀','元','元曲','yuanqu','','[]','怎禁那待漏东华风寒冒。',144,'元曲/yuanqu.json','["怎禁那待漏东华风寒冒。", "(吕成云)敢是饥饱劳役？(正末唱)公事冗伤饥饱。", "(吕成云)这病敢是风寒暑湿？(正末唱)皆因是年纪老。", "(吕成云)服药如何？(正末唱)则这内外相伤病难熬。", "(吕成云)别请个医人看视咱。", "(正末唱)这症候要和调，(吕成云)医人审其症源，服药必痊也。", "(正末唱)便有那扁鹊难医疗。"]'),
('yuanqu-7446','保成公径赴渑池会・沉醉东风','高文秀','元','元曲','yuanqu','','[]','则俺这文共武并无差错，过如那弟兄每岂有情薄？俺须是一殿臣，胜似那通家好，煞强如晏平仲善与人交。',435,'元曲/yuanqu.json','["则俺这文共武并无差错，过如那弟兄每岂有情薄？俺须是一殿臣，胜似那通家好，煞强如晏平仲善与人交。", "(吕成云)丞相与廉将军，都是尽忠肱股一殿之臣，勿念旧仇。", "(正末唱)俺两个竭力推诚辅圣朝，(吕成云)论赵国，丞相与廉将军，安邦定国之臣也。", "(正末唱)怎做的立国安邦的这大宝？(吕成云)丞相，小官改日迎门来望。", "小官告回也。", "(正末云)先生少罪。", "(吕成做出门见廉将军科)(廉颇云)参谋，相如语言可是如何？(吕成云)是你之差矣。", "恰才相如丞相言说，见今秦国不敢加兵于赵者，徒以我两人在也。", "今两虎共斗，其势不俱生。", "所以为此者，先国家之急，而后私仇也。", "小官看相如乃仁人君子之心，将军不及者多矣！(下)(廉颇云)既然相如有如此宽洪之量，尽心报国，某之不及。", "则今日肉袒负荆，至门谢罪，可为刎颈之交也。", "(做到门科，云)左右报复去，有廉将军叩门，负荆请罪来。", "(虞候云)理会的。", "报的大夫得知，廉将军在于门首。", "(正末云)做甚么？(虞候云)有廉将军负荆请罪来。", "(正末云)在那里？(虞候云)在门首。", "(正末唱)。"]'),
('yuanqu-7447','保成公径赴渑池会・落梅花','高文秀','元','元曲','yuanqu','','[]','则听的吵吵的人喧闹，我悠悠的魂魄消，(出门科，唱)原来是廉将军叩门来到。',136,'元曲/yuanqu.json','["则听的吵吵的人喧闹，我悠悠的魂魄消，(出门科，唱)原来是廉将军叩门来到。", "(廉颇云)大夫，廉颇乃一愚鲁之人，不晓仁义，多有失礼，万望大夫恕罪。", "(正末做跪科，云)将军请起。", "(廉颇云)大夫，看俺一殿之臣，旧日之交，休得见怪。", "(正末唱)恐嗔拳又向我这身上拷，我为甚忙陪着笑容哀告。"]'),
('yuanqu-7448','保成公径赴渑池会・殿前欢','高文秀','元','元曲','yuanqu','','[]','咱今日自评跋，(廉颇云)看咱一殿之臣，休记旧冤。',212,'元曲/yuanqu.json','["咱今日自评跋，(廉颇云)看咱一殿之臣，休记旧冤。", "(正末唱)我和你是风云会上旧臣僚。", "(廉颇云)大夫，赵国有咱文武二人之勇，不惧各国英雄。", "(正末唱)见如今偏邦岂敢侵边徼？(廉颇云)都皆惧咱文武二人。", "(正末唱)惧怕俺这文武英豪。", "你便似紫金梁架海涛，我似那白玉柱侵云表。", "(廉颇云)前者筵宴之间，不合愚鲁，有伤弟兄之情。", "(正末唱)若自伤损相残暴，则恐怕倾颓了赵国，(廉颇云)大夫，我的不是了，今日悔之不及也。", "(正末唱)我则怕畅快秦朝。"]'),
('yuanqu-7449','保成公径赴渑池会・水仙子','高文秀','元','元曲','yuanqu','','[]','堂堂阵势喊声高，赳赳军卒战鼓敲，重重鞍马征云罩。',72,'元曲/yuanqu.json','["堂堂阵势喊声高，赳赳军卒战鼓敲，重重鞍马征云罩。", "全在这大将军气势豪，破秦邦定在今朝。", "廉元帅施《三略》，蔺相如运《六韬》保山河共立勋劳。", "(同下)。"]'),
('yuanqu-7450','保成公径赴渑池会・雁儿落','高文秀','元','元曲','yuanqu','','[]','旗开云影飘，炮响雷霆噪。',24,'元曲/yuanqu.json','["旗开云影飘，炮响雷霆噪。", "弓开秋月圆，箭发流星落。"]'),
('yuanqu-7451','保成公径赴渑池会・得胜令','高文秀','元','元曲','yuanqu','','[]','霎时间尸首积山高，鲜血滚波涛。',448,'元曲/yuanqu.json','["霎时间尸首积山高，鲜血滚波涛。", "觅子寻爷叫，呼兄唤弟号。", "俺将帅雄骁，恰便似撞雾天边鹞。", "他军马奔逃，恰便似飘风云外鹤。", "(做拿净康皮力、范当灾科)(廉颇云)大夫，小官今日将秦国二将活挟将来了，将众兵斩尽杀绝也。", "(正末云)咱见主公去来。", "(同下)(赵成公领卒子上，云)某乃赵成公是也。", "自渑池会上以回，廉颇将军与大夫相如不睦，某使令人与他二人圆和，廉将军负荆请罪，结为刎颈之交。", "正酒筵之间，有秦将领兵索战。", "他文武二人，领着赵兵，与秦将交锋。", "此一去，必然得胜也。", "左右门首看者，若来时，报复我知道。", "(卒子云)理会的。", "(正末同廉颇上)(廉颇云)大夫，今日擒拿秦国二将在此。", "(正末云)执缚了那厮，见主公去来。", "(廉颇云)可早来到也。", "左右报复去，道相如、廉颇来了也。", "(卒子云)理会的。", "(报科，云)喏，报的主公得知，有相如、廉颇来了也。", "(赵成公云)着他过来。", "(做见科)(赵成公云)您二位将军，鞍马上劳神也。", "(正末云)托主公虎威，将贼将活拿将来了也。", "(赵成公云)多亏二位将军擒拿了贼子也。", "(正末云)这一场功劳，多亏廉将军也。"]'),
('yuanqu-7452','保成公径赴渑池会・沽美酒','高文秀','元','元曲','yuanqu','','[]','败残军尽捕剿，擒贼首献皇朝。',63,'元曲/yuanqu.json','["败残军尽捕剿，擒贼首献皇朝。", "驰骋凶顽显暴骄，强要俺无瑕玉宝，渑池会痛凌虐。", "(赵成公云)则今日安排筵宴，加官赐赏也。", "(正末唱)。"]'),
('yuanqu-7453','保成公径赴渑池会・太平令','高文秀','元','元曲','yuanqu','','[]','将鼓瑟筵前奏乐，捧金钟笑里藏刀。',54,'元曲/yuanqu.json','["将鼓瑟筵前奏乐，捧金钟笑里藏刀。", "背伦教有伤伦教，行霸道不遵王道。", "将这厮绑到市曹，处决一刀，俺设筵宴三军赏犒。"]'),
('yuanqu-7454','保成公径赴渑池会・折桂令','高文秀','元','元曲','yuanqu','','[]','则见这金銮殿乐奏箫韶。',295,'元曲/yuanqu.json','["则见这金銮殿乐奏箫韶。", "(赵成公云)因你二人齐家治国，竭力尽忠，故设筵宴管待也。", "(正末唱)将他这宝篆香飘，绛蜡光摇。", "(廉颇云)大夫，咱托一人之洪福，定七国之干戈，天下太平，万民安乐也。", "(正末唱)见如今万剩登基，百司进礼，四海来朝。", "(赵成公云)因为你于国有功，今日个封官赐赏也。", "(正末唱)今日个褒功绩升官进爵，赏勋劳裂土分茅。", "(廉颇云)岂不闻一人有庆，兆民赖之也！(正末唱)见如今黎庶歌谣，雨顺风调，万世皇图，地厚天高。", "(赵成公云)则为那渑池会上结仇冤，赵国公卿有二贤。", "武将廉颇安社稷，相如谋略古今传。", "加你为上卿之职头庭相，廉颇你总领三军金印悬。", "今日个文臣武将安天下，永保皇朝万万年。", "(同下)。"]'),
('yuanqu-7455','仙吕・村里迓鼓隐逸','贯石屏','元','元曲','yuanqu','','[]','我向这水边林下，盖一座竹篱茅舍。',74,'元曲/yuanqu.json','["我向这水边林下，盖一座竹篱茅舍。", "闲时节观山玩水，闷来和渔樵闲话。", "我将这绿柳栽，黄菊种，山林如画。", "闷来时看翠山，观绿水，指落花，呀，锁住我这心猿意马。"]'),
('yuanqu-7456','元和令・将柴门掩落霞，明月向杖头挂。我则见青山影里钓鱼槎，慢腾腾','贯石屏','元','元曲','yuanqu','','[]','间潇洒。',19,'元曲/yuanqu.json','["间潇洒。", "闷来独自对天涯，荡村醪饮兴加。"]'),
('yuanqu-7457','上马娇・鱼旋拿，柴旋打。无事掩荆笆，醉时节卧在葫芦架。咱，睡起时','贯石屏','元','元曲','yuanqu','','[]','节旋去烹茶。',6,'元曲/yuanqu.json','["节旋去烹茶。"]'),
('yuanqu-7458','游四门・药炉经卷作生涯，学种邵平瓜。渊明赏菊在东篱下，终日饮流霞。','贯石屏','元','元曲','yuanqu','','[]','咱，向炉内炼丹砂。',9,'元曲/yuanqu.json','["咱，向炉内炼丹砂。"]'),
('yuanqu-7459','胜葫芦・我则待散诞逍遥闲笑耍，左右种桑麻，闲看园林噪晚鸦。心无牵','贯石屏','元','元曲','yuanqu','','[]','挂，蹇驴闲跨，游玩野人家。',13,'元曲/yuanqu.json','["挂，蹇驴闲跨，游玩野人家。"]'),
('yuanqu-7460','后庭花・我将这嫩蔓菁带叶煎，细芋糕油内炸。白酒磁杯咽，野花头上插。','贯石屏','元','元曲','yuanqu','','[]','兴来时笑呷呷，村醪饮罢。',33,'元曲/yuanqu.json','["兴来时笑呷呷，村醪饮罢。", "绕柴扉水一洼，近山村看落花，是蓬莱天地家。"]'),
('yuanqu-7461','青哥儿・呀，看一带云山，云山如画，端的是景物，景物堪夸。剩下残山','贯石屏','元','元曲','yuanqu','','[]','向那答？心无牵挂，树林之下，椰瓢高挂。',38,'元曲/yuanqu.json','["向那答？心无牵挂，树林之下，椰瓢高挂。", "冷清清无是无非诵《南华》。", "这里乾坤大。"]'),
('yuanqu-7462','仙吕・青哥儿十二月正月','马致远','元','元曲','yuanqu','','[]','春城春宵无价，照星桥火树银花。',449,'元曲/yuanqu.json','["春城春宵无价，照星桥火树银花。", "妙舞清歌最是他，翡翠坡前那人家，鳌山下。", "二月前村梅花开尽，看东风桃李争春。", "宝马香车陌上尘，两两三三见游人，清明近。", "三月风流城南修禊，曲江头丽人天气。", "红雪飘香翠雾迷，御柳宫花几曾知，春归来。", "四月东风园林昨暮，被啼莺唤将春去。", "煮酒青梅尽醉渠，留下西楼美人图，闲情赋。", "五月榴花葵花争笑，先生醉读《离骚》。", "卧看风檐燕垒巢，忽听得江津戏兰桡，船儿闹。", "六月冰壶瑶台天远，逃炎蒸莫要逃禅。", "约下新秋数日前，闲与仙人醉秋莲，凌波殿。", "七月梧桐初雕金井，月纤妍人自娉婷。", "独对青娥翠画屏，闲只管银河问双星，无蹊径。", "八月铜壶半分更漏，散秋香桂娥将就。", "天远云归月满楼，这清兴谁教庾江州，能消受。", "九月前年维舟寒濑，对蓬窗丛菊花开。", "陈迹犹存戏马台，说道丹阳寄奴来，愁无奈。", "十月玄冥偷传春信，只多为腊蕊冰痕。", "山远楼高雪意新，锦帐佳人会温存，添风韵。", "十一月当年东君生意，在重泉一阳机会。", "与物无心总不知，律管儿女漫吹灰，闲游戏。", "十二月隆冬寒严时节，岁功来待将迁谢。", "爱惜梅花积下雪，分付与东君略添些，丰年也。"]'),
('yuanqu-7463','南吕・四块玉恬退','马致远','元','元曲','yuanqu','','[]','绿鬓衰，朱颜改，羞把尘容画麟台，故园风景依然在。',150,'元曲/yuanqu.json','["绿鬓衰，朱颜改，羞把尘容画麟台，故园风景依然在。", "三顷田，五亩宅，归去来。", "绿水边，青山侧，二顷良田一区宅，闲身跳出红尘外。", "紫蟹肥，黄菊开，归去来。", "翠竹边，青松侧，竹影松声两茅斋，太平幸得闲身在。", "三径修，五柳栽，归去来。", "酒旋沽，鱼新买，满眼云山画图开，清风明月还诗债。", "本是个懒散人，又无甚经济才，归去来。"]'),
('yuanqu-7464','南吕・四块玉天台路','马致远','元','元曲','yuanqu','','[]','采药童，乘鸾客，怨感刘郎下天台。',449,'元曲/yuanqu.json','["采药童，乘鸾客，怨感刘郎下天台。", "春风再到人何在？桃花又不见开。", "命薄的穷秀才，谁教你回去来！紫芝路雁北飞，人北望，抛闪煞明妃也汉君王。", "小单于把盏呀剌剌唱。", "青草畔有收酪牛，黑河边有扇尾羊，他只是思故乡。", "浔阳江送客时，秋江冷，商女琵琶断肠声。", "可知道司马和愁听。", "月又明，酒又醒，客乍醒。", "马嵬坡睡海棠，春将晚，恨不得明皇掌中看。", "《霓裳》便是中原患。", "不因这玉环，引起那禄山，怎知蜀道难！凤凰坡百尺台，堆黄壤，弄玉吹箫送萧郎。", "送萧郎共上青霄上。", "到如今国已亡，想当初事可伤，再几时有凤凰？蓝桥驿玉杵闲，玄霜尽，何敢蓝桥望行云？裴航自有神仙分。", "原是个窃玉人，做了个赏月人，成就了折桂人。", "洞庭湖画不成，西施女，他本倾城却倾吴。", "高哉范蠡乘舟去。", "那里是泛五湖？若纶竿不钓鱼，便索他学楚大夫。", "临邛市美貌才，名家子，自驾着个私奔坐车儿。", "汉相如便做文章士。", "爱他那一操儿琴，共他那两句儿诗，也有改嫁时。", "巫山庙暮雨迎，朝云送，暮雨朝云去无踪。", "襄王谩说阳台梦。", "云来也是空，雨来也是空，怎捱十二峰。", "海神庙彩扇歌，青楼饮，自是知音惜知音。"]'),
('yuanqu-7465','南吕・四块玉叹世','马致远','元','元曲','yuanqu','','[]','两鬓皤，中年过，图甚区区苦张罗？人间宠辱都参破。',372,'元曲/yuanqu.json','["两鬓皤，中年过，图甚区区苦张罗？人间宠辱都参破。", "种春风二顷田，远红尘千丈波，倒大来闲快活。", "子孝顺，妻贤惠，使碎心机为他谁？到头来难免无常日。", "争名利，夺富贵，都是痴。", "带野花，携村酒，烦恼如何到心头。", "谁能跃马常食肉？二顷田，一具牛，饱后休。", "佐国心，拿云手，命里无时莫刚求。", "随时过遣休生受。", "几叶绵，一片绸，暖后休。", "带月行，披星走，孤馆寒食故乡秋。", "妻儿胖了咱消瘦。", "枕上忧，马上愁，死后休。", "白玉堆，黄金垛，一日无常果如何？良辰媚景休空过。", "琉璃钟琥珀浓，细腰舞皓齿歌，倒大来闲快活。", "风内灯，石中火，从结灵胎便南柯，福田休种儿孙祸。", "结三生清净缘，住一区安乐窝，倒大来闲快活。", "月满轮，花成朵，信马携仆到鸣珂，选一间岩嵌房儿坐。", "浅斟着金曲卮，低讴着白雪歌，倒大来闲快活。", "甑有尘，门无锁，人海从教斗张罗。", "共诗朋闲访相酬和，尽场儿吃闷酒，即席间发淡科，倒大来闲快活。"]'),
('yuanqu-7466','中吕・喜春来六艺礼','马致远','元','元曲','yuanqu','','[]','夙兴夜寐尊师行，动止浑绝浮浪名，身潜诗礼且陶情。',209,'元曲/yuanqu.json','["夙兴夜寐尊师行，动止浑绝浮浪名，身潜诗礼且陶情。", "柳溪中，人世小蓬瀛。", "乐宫商律吕随时秦，散虑焚香理素琴，人和神悦在佳音。", "不关心，玉漏滴残淋。", "射古来射席观其德，今向樽前自乐心，醉横壶矢卧蓑阴。", "且闲身，醒踏月明吟。", "御昔驰铁骑经燕赵，往复奔腾稳似船，今朝两鬓已成斑。", "机自参，牛背得身安。", "书笔尖落纸生云雾，扫出龙蛇惊四筵，蛮书写毕动君颜。", "酒中仙，一恁醉长安。", "数盈虚妙自胸中蓄，万事幽传一掌间，不如长醉酒垆边。", "是非潜，终日乐尧年。"]'),
('yuanqu-7467','越调・天净沙秋思','马致远','元','元曲','yuanqu','','[]','枯藤老树昏鸦，小桥流水人家，古道西风瘦马。',33,'元曲/yuanqu.json','["枯藤老树昏鸦，小桥流水人家，古道西风瘦马。", "夕阳西下，断肠人在天涯。"]'),
('yuanqu-7468','双调・蟾宫曲叹世','马致远','元','元曲','yuanqu','','[]','东篱半世蹉跎，竹里游亭，小宇婆娑。',128,'元曲/yuanqu.json','["东篱半世蹉跎，竹里游亭，小宇婆娑。", "有个池塘，醒时渔笛，醉后渔歌。", "严子陵他应笑我，孟光台我待学他。", "笑我如何？倒大江湖，也避风波。", "咸阳百二山河，两字功名，几阵干戈。", "项废东吴，刘兴西蜀，梦说南柯。", "韩信功兀的般证果，蒯通言那里是风魔？成也萧何，败也萧何，醉了由他。"]'),
('yuanqu-7469','双调・清江引野兴','马致远','元','元曲','yuanqu','','[]','樵夫觉来山月底，钓叟来寻觅。',298,'元曲/yuanqu.json','["樵夫觉来山月底，钓叟来寻觅。", "你把柴斧抛，我把鱼船弃。", "寻取个稳便处闲坐地。", "绿蓑衣紫罗袍谁是主，两件儿都无济。", "便作钓鱼人，也在风波里。", "则不如寻个稳便处闲坐地。", "山禽晓来窗外啼，唤起山翁睡。", "恰道不如归，又叫行不得。", "则不如寻个稳便处闲坐地。", "天之美禄谁不喜？偏则说刘伶醉，毕卓缚瓮边，李白沉江底。", "则不如寻个稳便处闲坐地。", "楚霸王火烧了秦宫室，盖世英雄气。", "阴陵迷路时，船渡乌江际。", "则不如寻个隐便个闲坐地。", "林泉隐居谁到此？有客清风至。", "会作山中相，不管人间事。", "争甚么半张名利纸！西村日长人事少，一个新蝉噪。", "恰待葵花开，又早蜂儿闹，高枕上梦随蝶去了东篱本是风月主，晚节园林趣。", "一枕葫芦架，几行垂杨树，是搭儿快活闲住处。"]'),
('yuanqu-7470','双调・寿阳曲山市晴岚','马致远','元','元曲','yuanqu','','[]','花村外，草店西，晚霞明雨收天霁。',288,'元曲/yuanqu.json','["花村外，草店西，晚霞明雨收天霁。", "四围山一竿残照里，锦屏风又添铺翠。", "远浦帆归夕阳下，酒旆闲，两三航未曾着岸。", "落花水香茅舍晚，断桥头卖鱼人散。", "平沙落雁南传信，北寄书，半栖近岸花汀树。", "似鸳鸯失群迷伴侣，两三行海门斜去。", "潇湘夜雨渔灯暗，客梦回，一声声滴人心碎。", "孤舟五更家万里，是离人几行情泪。", "烟寺晚钟寒烟细，古寺清，近黄昏礼佛人静。", "顺西风晚钟三四声，怎生教老僧禅定？渔村夕照鸣榔罢，闪暮光，绿杨堤数声渔唱。", "挂柴门几家闲晒网，都撮在捕鱼图上。", "江天暮雪天将暮，雪乱舞，半梅花半飘柳絮。", "江上晚来堪画处，钓鱼人一蓑归去。", "洞庭秋月芦花谢，客乍别，泛蟾光小舟一叶。", "豫章城故人来也，结末了洞庭秋月。"]'),
('yuanqu-7471','双调・湘妃怨和卢疏斋《西湖》','马致远','元','元曲','yuanqu','','[]','春风骄马五陵儿，暖日西湖三月时，管弦触水莺花市。',239,'元曲/yuanqu.json','["春风骄马五陵儿，暖日西湖三月时，管弦触水莺花市。", "不知音不到此，宜歌宜酒宜诗。", "山过雨颦眉黛，柳拖烟堆鬓丝。", "可喜杀睡足的西施。", "采莲湖上画船儿，垂钓滩头白鹭鸶。", "雨中楼阁烟中寺，笑王维作画师。", "蓬莱倒影参差。", "薰风来至，荷香净时。", "清洁煞避暑的西施。", "金卮满劝莫推辞，已是黄柑紫蟹时。", "鸳鸯不管伤心事，便白头湖上死。", "爱园林一抹胭脂，霜落在丹枫上，水飘着红叶儿。", "风流煞带酒的西施。", "人家篱落酒旗儿，雪压寒梅老树枝。", "吟诗未稳推敲字，为西湖捻断髭，恨东坡对雪无诗。", "休道是苏学士，韩退之，难装煞傅粉的西施。"]'),
('yuanqu-7472','双调・庆东原叹世','马致远','元','元曲','yuanqu','','[]','拔山力，举鼎威，暗鸣叱咤千人废。',272,'元曲/yuanqu.json','["拔山力，举鼎威，暗鸣叱咤千人废。", "阴陵道北，乌江岸西，休了衣锦东归，不如醉还醒，醒而醉。", "明月闲旌旆，秋风助鼓鼙，帐前滴尽英雄泪。", "楚歌四起，乌骓漫嘶，虞美人兮，不如醉还醒，醒而醉。", "三顾茅庐问，高才天下知，笑当时诸葛成何计？出师未回，长星坠地，蜀国空悲，不如醉还醒，醒而醉。", "夸才智，曹孟德，分香卖履纯狐媚。", "奸雄那里？平生落的，只两字征西。", "不如醉还醒，醒而醉。", "画筹计，堕泪碑，两贤才德谁相配？一个力扶汉基，一个恢张晋室，可惜都寿与心违，不如醉还醒，醒而醉。", "珊瑚树，高数尺，珍奇合在谁家内？便认做我的，岂不知财多害已，直到东市方知。", "则不如醉还醒，醒而醉。"]'),
('yuanqu-7473','双调・拨不断','马致远','元','元曲','yuanqu','','[]','九重天，二十年，龙楼凤阁都曾见。',609,'元曲/yuanqu.json','["九重天，二十年，龙楼凤阁都曾见。", "绿水青山任自然，旧时王谢堂前燕，再不复海棠庭院。", "叹寒儒，谩读书，读书须索题桥柱。", "题柱虽乘驷马车，乘车谁买《长门赋》？且看了长安回去。", "路旁碑，不知谁，春苔绿满无人祭。", "毕卓生前酒一杯，曹公身后坟三尺，不如醉了还醉。", "怨离别，恨离别，君知君恨君休惹。", "红日如奔过隙驹，白头渐满杨花雪，一日一个渭城客舍。", "孟襄阳，兴何狂？冻骑驴灞陵桥上，便纵有些梅花入梦香，到不如风雪销金帐，慢慢的浅斟低唱。", "笑陶家，雪烹茶，就鹅毛瑞雪初成腊，见蝶翅寒梅正有花，怕羊羔美酒新添价，拖得人冷斋里闲话。", "菊花开，正归来。", "伴虎溪僧鹤林友龙山客，似杜工部陶渊明李太白，有洞庭柑东阳酒西湖蟹。", "哎？楚三闾休怪。", "浙江亭，看潮生，潮来潮去原无定，惟有西山万古青。", "子陵一钓多高兴，闹中取静。", "酒杯深，故人心，相逢且莫推辞饮。", "君若歌时我慢斟，屈原清死由他恁。", "醉和醒争甚？瘦形骸，闷情怀，丹枫醉倒秋山色，黄菊雕残戏马台，白衣盼杀东篱客，你莫不子猷访戴？布衣中，问英雄，王图霸业成何用！禾黍高低六代宫，楸梧远近千官冢，一场恶梦。", "竞江山，为长安，张良放火连云栈，韩信独登拜将坛，霸王自刎乌江岸，再谁分楚汉。", "子房鞋，买臣柴，屠沽乞食为僚宰，版筑躬耕有将才。", "古人尚自把天时待，只不如且酩子里胡捱。", "莫独狂，祸难防，寻思乐毅非良将，直待齐邦扫地亡，火牛一战几乎丧，赶人休赶上。", "立峰峦，脱簪冠。", "夕阳倒影松阴乱，太液澄虚月影宽，海风汗漫云霞断，醉眠时小童休唤。"]'),
('yuanqu-7474','仙吕・赏花时长江风送客','马致远','元','元曲','yuanqu','','[]','冯客苏卿先配成，愁杀风流双县令。',35,'元曲/yuanqu.json','["冯客苏卿先配成，愁杀风流双县令。", "扑簌簌泪如倾，凄凉愁损，相伴着短檠灯。"]'),
('yuanqu-7475','幺・愁恨厌厌魂梦惊，两处相思一样情。风送片帆轻，天涯隐隐，船去似','马致远','元','元曲','yuanqu','','[]','驭云行。',4,'元曲/yuanqu.json','["驭云行。"]'),
('yuanqu-7476','赚煞・碧波清，江天静，既解缆如何住程？灭烛掀帘风越紧，转回头又到','马致远','元','元曲','yuanqu','','[]','山城。',77,'元曲/yuanqu.json','["山城。", "过沙汀，烟水澄澄，千里洪波良夜永。", "蛾眉月明，恰才风定，猛抬头观见豫章城。", "孤馆雨留人鞍马区区山路遥，月暗星稀天欲晓，云气布荒郊。", "前途店少，仅此避风雹。"]'),
('yuanqu-7477','幺・不觉楼头二鼓过，慢撒金莲鸣玉珂。离香阁近花科，丫鬟唤我，渴睡','马致远','元','元曲','yuanqu','','[]','也去来呵。',5,'元曲/yuanqu.json','["也去来呵。"]'),
('yuanqu-7478','赚煞・紧相催，闲笃磨，快道与茶茶嬷嬷。宝鉴妆奁准备着，就这月华明','马致远','元','元曲','yuanqu','','[]','乘兴梳裹，喜无那，非是咱风魔，伸玉指盆池内蘸绿波。',86,'元曲/yuanqu.json','["乘兴梳裹，喜无那，非是咱风魔，伸玉指盆池内蘸绿波。", "刚绰起半撮，小梅香也歇和，分明掌上见嫦娥。", "弄花香满衣丽日迟迟帘影筛，燕子来时花正开。", "闲绣阁冷妆台，兜鞋信步，后园里遣闷怀。"]'),
('yuanqu-7479','幺・万紫千红妖弄色，娇态难禁风力摆。时乱点尘埃，见秋千挂起，芳草','马致远','元','元曲','yuanqu','','[]','上层阶。',4,'元曲/yuanqu.json','["上层阶。"]'),
('yuanqu-7480','南吕・一枝花惜春','马致远','元','元曲','yuanqu','','[]','夺残造化功，占断繁华富，芳名喧上苑，和气满皇都。',64,'元曲/yuanqu.json','["夺残造化功，占断繁华富，芳名喧上苑，和气满皇都。", "论春秀谁如，一任教浪蕊闲花坞。", "正是断人肠三月初，本待学煮海张生，生扭做游春杜甫。"]'),
('yuanqu-7481','隔尾・休耽阁一天柳絮如绵舞，满地残花似锦铺，九十日春光等闲负。云','马致远','元','元曲','yuanqu','','[]','窗月户，狂风聚雨，休没乱杀东君做不得主。',20,'元曲/yuanqu.json','["窗月户，狂风聚雨，休没乱杀东君做不得主。"]'),
